import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { KATHARA_GRID_NODES, KATHARA_GRID_LINES, KATHARA_CLOCK_POINTS, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, MUQATTAT_LETTERS } from '../constants.ts';
import { getSliceAtPoint } from '../utils.ts';

interface TreeOfLifeModeProps {
  rotation: number;
  onClose: () => void;
}

const PRESET_1 = [
  "Book", "Chosen One | Rasul", "Sign", "Prophet", "Challenge | Rescue", "Curse", 
  "Blessed Land", "Believer | Servant", "Suhuf", "Teacher", "Witness | Driver", "Stone"
];

const PRESET_2 = [
  "Ibrahim | Yahya",
  "Rushd",
  "Challenge",
  "Destroy",
  "Witness",
  "Battle | Pit",
  "Solomon | Musa",
  "Zabur",
  "Dawud",
  "High Ground",
  "Palm Date Tree",
  "Action | Word"
];

const PRESET_3 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Rushd",
  "Stone",
  "Iron | Wood",
  "Noah | Musa",
  "Idris | Isa",
  "Iron | Mountain",
  "Amanah",
  "Dawud",
  "Solomon | Death",
  "Book | Yahya"
];

interface BifurcationStage {
  main: number[];
  manualLines: [number, number][];
  isBlackPhase?: boolean;
}

const TreeOfLifeMode: React.FC<TreeOfLifeModeProps> = ({ rotation, onClose }) => {
  const [labels, setLabels] = useState<string[]>(Array(12).fill(''));
  const [labelOffset, setLabelOffset] = useState(0); 
  const [isCycling, setIsCycling] = useState(false);
  const [activeMode, setActiveMode] = useState<'linear' | 'bifurcation'>('linear');
  const [highlightedNodes, setHighlightedNodes] = useState<number[]>([]);

  const [showLightning, setShowLightning] = useState(false);
  const [showExplosion, setShowExplosion] = useState(false);

  // Domain Node Sets
  const BLUE_NODES = [1, 2, 3, 4, 5, 6, 13];
  const GREEN_NODES = [12, 11, 10, 9, 8, 7, 15];

  const LOOP_LINES: [number, number][] = [[2, 3], [3, 6], [6, 9], [9, 11], [11, 10], [10, 7], [7, 4], [4, 2]];
  const BOLT_3_10_LINES: [number, number][] = [[3, 13], [4, 13], [4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9], [9, 15], [10, 15]];
  const BOLT_4_9_LINES: [number, number][] = [[4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9]];
  const PATH_5_8_LINES: [number, number][] = [[5, 6], [6, 14], [7, 14], [7, 8]];
  const CROSS_PLUS_LINES: [number, number][] = [[6, 14], [7, 14], [5, 14], [14, 8], [6, 7], [5, 8]];

  const DUAL_GROUP_LINES: [number, number][] = [
    [1, 2], [2, 3], [2, 4], [2, 13], [3, 13], [4, 13], [3, 5], [4, 5], [5, 6], [3, 6], [13, 5],
    [12, 11], [11, 10], [11, 9], [9, 15], [10, 15], [15, 8], [8, 9], [8, 10], [7, 8], [7, 10], [15, 11]
  ];
  const SQUARE_PLUS_LINES: [number, number][] = [[5, 6], [5, 7], [6, 8], [7, 8], [6, 14], [14, 7], [5, 14], [14, 8]];

  const BIFURCATION_STAGES: BifurcationStage[] = useMemo(() => [
    { main: [1, 12], manualLines: [], isBlackPhase: true },
    { main: [2, 11], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: CROSS_PLUS_LINES },
    { main: [12, 1], manualLines: DUAL_GROUP_LINES },
    { main: [11, 2], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: SQUARE_PLUS_LINES },
  ], []);

  const handleSyncFromWheel = (mode: 'full' | 'title') => {
    const newLabels = KATHARA_CLOCK_POINTS.map(pointValue => {
        const slice = getSliceAtPoint(pointValue, rotation);
        const chapterInfo = CHAPTER_DETAILS.find(c => c.number === slice.id);
        const title = chapterInfo?.englishName || 'Unknown';
        const letters = MUQATTAT_LETTERS.get(slice.id)?.join(' ') || '';
        if (mode === 'title') return `${title}${letters ? ` | ${letters}` : ''}`;
        return `${slice.id} ${title}${letters ? ` | ${letters}` : ''}`;
    });
    setLabels(newLabels);
    setLabelOffset(0);
  };

  const handlePreset = (num: number) => {
    setLabelOffset(0);
    setHighlightedNodes([]);
    setIsCycling(false);
    if (num === 0) setLabels(Array(12).fill(''));
    else if (num === 1) setLabels([...PRESET_1]);
    else if (num === 2) setLabels([...PRESET_2]);
    else if (num === 3) setLabels([...PRESET_3]);
  };

  const updateVisuals = useCallback((offset: number) => {
    if (activeMode === 'linear') setHighlightedNodes([offset + 1]);
    else setHighlightedNodes(BIFURCATION_STAGES[offset].main);
  }, [activeMode, BIFURCATION_STAGES]);

  const handleShift = useCallback((direction: 'up' | 'down') => {
    setLabelOffset((prev) => {
      const next = direction === 'up' ? (prev + 1) % 12 : (prev - 1 + 12) % 12;
      if (activeMode === 'bifurcation') {
        if (prev === 11 && next === 0) { setShowLightning(true); setTimeout(() => setShowLightning(false), 800); }
        if (prev === 5 && next === 6) { setShowExplosion(true); setTimeout(() => setShowExplosion(false), 1200); }
      }
      updateVisuals(next);
      return next;
    });
  }, [updateVisuals, activeMode]);

  useEffect(() => { updateVisuals(labelOffset); }, [activeMode, updateVisuals, labelOffset]);

  useEffect(() => {
    if (!isCycling) return;
    const intervalId = window.setInterval(() => { handleShift('up'); }, 1800);
    return () => clearInterval(intervalId);
  }, [isCycling, handleShift]);

  const updateLabel = (index: number, val: string) => {
    const next = [...labels];
    next[index] = val;
    setLabels(next);
  };

  const getLineStatus = useCallback((from: number, to: number, h: number[], offset: number) => {
    if (activeMode === 'linear') {
      const nodeId = h[0];
      return from === nodeId || to === nodeId ? 'main' : null;
    }
    const stage = BIFURCATION_STAGES[offset];
    if (stage.isBlackPhase) return 'black';
    const isManual = stage.manualLines?.some(l => (l[0] === from && l[1] === to) || (l[0] === to && l[1] === from));
    return isManual ? 'main' : null;
  }, [activeMode, BIFURCATION_STAGES]);

  const getDisplayIdx = useCallback((nodeIdx: number, offset: number, mode: 'linear' | 'bifurcation') => {
    if (mode === 'linear') return (nodeIdx - offset + 12) % 12;
    const step = offset % 6;
    const hasCrossed = offset >= 6;
    if (nodeIdx < 6) return hasCrossed ? (nodeIdx - step + 6) % 6 + 6 : (nodeIdx - step + 6) % 6;
    return hasCrossed ? (11 - nodeIdx - step + 6) % 6 : (11 - nodeIdx - step + 6) % 6 + 6;
  }, []);

  const renderDiagram = () => {
    const isPhase2or8 = activeMode === 'bifurcation' && (labelOffset === 1 || labelOffset === 7);
    const extraSilverLines = isPhase2or8 ? [[9, 7], [6, 4]] : [];

    return (
      <div className="relative flex items-center justify-center bg-black/80 overflow-hidden h-full w-full rounded-3xl lg:rounded-none">
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[90%] h-[90%] rounded-full bg-cyan-950/10 blur-[120px] lg:blur-[180px]"></div>
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000_100%)] opacity-80"></div>
        </div>

        <style>{`
          .node-glow { filter: drop-shadow(0 0 15px currentColor); }
          .kathara-svg { width: 100%; height: 100%; max-height: 85vh; padding: 20px; }
          .junction-box { stroke-width: 1; fill: rgba(0, 0, 0, 0.85); stroke: rgba(255, 255, 255, 0.1); }
          .active-junction { stroke: #fff; stroke-width: 1.5; fill: rgba(8, 145, 178, 0.3); }
          .filter-junction { stroke: #06b6d4; fill: rgba(0, 30, 40, 0.9); }

          @keyframes flow-up { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }
          @keyframes flow-down { 0% { stroke-dashoffset: 0; } 100% { stroke-dashoffset: 40; } }
          @keyframes flow-silver { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }

          .liquid-blue-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-up 1.6s linear infinite; filter: drop-shadow(0 0 6px #06b6d4); }
          .liquid-green-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-down 1.6s linear infinite; filter: drop-shadow(0 0 6px #4ade80); }
          .liquid-silver-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-silver 1.6s linear infinite; filter: drop-shadow(0 0 6px #cbd5e1); }

          @keyframes spark { 0%, 100% { opacity: 0; stroke-width: 1; } 20% { opacity: 1; stroke-width: 4; } 60% { opacity: 1; stroke-width: 2; } }
          .lightning-bolt { stroke: #fff; filter: drop-shadow(0 0 12px cyan); animation: spark 0.25s infinite; }

          @keyframes blast { 0% { transform: scale(0); opacity: 1; filter: blur(0px); } 50% { transform: scale(3); opacity: 0.5; filter: blur(5px); } 100% { transform: scale(4.5); opacity: 0; filter: blur(10px); } }
          .fire-burst { fill: #f97316; animation: blast 0.8s ease-out forwards; }
        `}</style>

        <svg viewBox="-70 0 290 280" className="kathara-svg drop-shadow-[0_0_80px_rgba(6,182,212,0.15)]">
          <defs>
            <linearGradient id="activeGrad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#0891b2" />
              <stop offset="100%" stopColor="#06b6d4" />
            </linearGradient>
          </defs>

          <g>
            {KATHARA_GRID_LINES.map((line, index) => {
              const fromNode = KATHARA_GRID_NODES.find(n => n.id === line.from);
              const toNode = KATHARA_GRID_NODES.find(n => n.id === line.to);
              if (!fromNode || !toNode) return null;

              const status = getLineStatus(line.from, line.to, highlightedNodes, labelOffset);
              const isMain = status === 'main';
              const isAscending = fromNode.y > toNode.y;

              const isBlueDomain = (BLUE_NODES.includes(line.from) && BLUE_NODES.includes(line.to)) || 
                                  ((line.from === 14 || line.to === 14) && (BLUE_NODES.includes(line.from) || BLUE_NODES.includes(line.to)));

              const isGreenDomain = (GREEN_NODES.includes(line.from) && GREEN_NODES.includes(line.to)) || 
                                   ((line.from === 14 || line.to === 14) && (GREEN_NODES.includes(line.from) || GREEN_NODES.includes(line.to)));

              const isPhase12 = activeMode === 'bifurcation' && labelOffset === 11;
              const isSilverLine = isPhase12 && (
                (line.from === 6 && line.to === 8) || (line.from === 8 && line.to === 6) ||
                (line.from === 8 && line.to === 7) || (line.from === 7 && line.to === 8) ||
                (line.from === 7 && line.to === 5) || (line.from === 5 && line.to === 7) ||
                (line.from === 5 && line.to === 6) || (line.from === 6 && line.to === 5)
              );

              const showBlue = activeMode === 'linear' ? isMain : (isMain && isBlueDomain && !isSilverLine);
              const showGreen = activeMode === 'linear' ? isMain : (isMain && isGreenDomain && !isSilverLine);
              const showSilver = isMain && isSilverLine;

              const dx = toNode.x - fromNode.x;
              const dy = toNode.y - fromNode.y;
              const len = Math.sqrt(dx*dx + dy*dy);
              const nx = -dy / (len || 1);
              const ny = dx / (len || 1);
              const offsetDist = activeMode === 'linear' ? 2.0 : 0;

              return (
                <g key={index}>
                  <line 
                    x1={fromNode.x} y1={fromNode.y} 
                    x2={toNode.x} y2={toNode.y} 
                    stroke={isMain ? (isSilverLine ? "rgba(203,213,225,0.2)" : "rgba(255,255,255,0.12)") : status === 'black' ? "#0a0a0a" : "rgba(255,255,255,0.04)"}
                    strokeWidth={isMain ? 4 : 1}
                    className="transition-all duration-700"
                  />
                  {showBlue && <line x1={(isAscending ? fromNode.x : toNode.x) + nx * offsetDist} y1={(isAscending ? fromNode.y : toNode.y) + ny * offsetDist} x2={(isAscending ? toNode.x : fromNode.x) + nx * offsetDist} y2={(isAscending ? toNode.y : fromNode.y) + ny * offsetDist} stroke="#06b6d4" strokeWidth="3.5" className="liquid-blue-flow" />}
                  {showGreen && <line x1={(isAscending ? toNode.x : fromNode.x) - nx * offsetDist} y1={(isAscending ? toNode.y : fromNode.y) - ny * offsetDist} x2={(isAscending ? fromNode.x : toNode.x) - nx * offsetDist} y2={(isAscending ? fromNode.y : toNode.y) - ny * offsetDist} stroke="#4ade80" strokeWidth="3.5" className="liquid-green-flow" />}
                  {showSilver && <line x1={fromNode.x} y1={fromNode.y} x2={toNode.x} y2={toNode.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />}
                </g>
              );
            })}
            {extraSilverLines.map(([fromId, toId], idx) => {
              const f = KATHARA_GRID_NODES.find(n => n.id === fromId);
              const t = KATHARA_GRID_NODES.find(n => n.id === toId);
              if (!f || !t) return null;
              return (
                <g key={`extra-silver-${idx}`}>
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="rgba(203,213,225,0.4)" strokeWidth="3" />
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />
                </g>
              );
            })}
          </g>

          {showLightning && (
            <g className="pointer-events-none">
              <path d="M 75 20 L 95 60 L 55 100 L 75 140" fill="none" className="lightning-bolt" />
              <path d="M 30 140 L 55 170 L 35 200 L 75 240" fill="none" className="lightning-bolt" />
              <path d="M 120 140 L 95 170 L 115 200 L 75 240" fill="none" className="lightning-bolt" />
            </g>
          )}

          {showExplosion && (
            <g transform="translate(75, 140)" className="pointer-events-none">
              <circle r="12" className="fire-burst" />
              <circle r="8" className="fire-burst" style={{ animationDelay: '0.1s' }} />
            </g>
          )}

          {KATHARA_GRID_NODES.map((node, nodeIdx) => {
            const isFilter = node.id > 12;
            const isHighlighted = highlightedNodes.includes(node.id);
            const displayLabelIdx = isFilter ? -1 : getDisplayIdx(nodeIdx, labelOffset, activeMode);
            const rawLabel = isFilter ? '' : labels[displayLabelIdx];

            // Combined triplet labels as requested
            const filterFullLabel = node.id === 13 ? '△108⚡' : node.id === 14 ? '🔥103🐟' : node.id === 15 ? '⚫110🌳' : null;

            const labelParts = rawLabel ? rawLabel.split('|').map(p => p.trim()) : [];
            const hasMultiple = labelParts.length > 1;
            const isSpineNode = node.x === 75 && node.id <= 12; 
            const isLeftSide = node.x < 75;

            return (
              <g key={node.id} className="transition-all duration-500">
                {isFilter ? (
                  <g>
                    {isHighlighted && <rect x={node.x-28} y={node.y-12} width="56" height="24" rx="4" fill="rgba(6,182,212,0.15)" className="animate-pulse" />}
                    <rect x={node.x-25} y={node.y-10} width="50" height="20" rx="3" className={`filter-junction ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#06b6d4' }} />
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".35em" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#0891b2"} className="font-mono tracking-tighter" style={{ pointerEvents: 'none' }}>
                      {filterFullLabel}
                    </text>
                  </g>
                ) : (
                  <g>
                    <rect x={node.x-14} y={node.y-14} width="28" height="28" rx="6" className={`junction-box ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#fff' }} />
                    {isHighlighted && <circle cx={node.x} cy={node.y} r={22} fill="url(#activeGrad)" opacity="0.1" className="animate-pulse" />}
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".35em" fontSize="8" fontWeight="black" fill={isHighlighted ? "#fff" : "#555"}>{node.id}</text>
                    {rawLabel && (
                      <g className="pointer-events-none">
                         {isSpineNode && hasMultiple ? (
                          <>
                            <rect x={node.x - 76} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x - 22} y={node.y} textAnchor="end" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[0]}</text>
                            <rect x={node.x + 18} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x + 22} y={node.y} textAnchor="start" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[1]}</text>
                          </>
                         ) : (
                          <g>
                             <rect x={isLeftSide ? node.x - 76 : node.x + 18} y={node.y - (hasMultiple ? 14 : 9)} width="58" height={hasMultiple ? 28 : 18} rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                             <text x={isLeftSide ? node.x - 22 : node.x + 22} y={node.y} textAnchor={isLeftSide ? "end" : "start"} dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">
                               {hasMultiple ? (<><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="-0.5em">{labelParts[0]}</tspan><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="1.1em">{labelParts[1]}</tspan></>) : rawLabel}
                             </text>
                          </g>
                         )}
                      </g>
                    )}
                  </g>
                )}
              </g>
            );
          })}
        </svg>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#02040a] animate-in fade-in zoom-in duration-500 overflow-y-auto lg:overflow-hidden">
      <aside className="w-full lg:w-[420px] h-fit lg:h-full p-8 border-b lg:border-r border-white/10 flex flex-col space-y-6 bg-black/40 backdrop-blur-xl shrink-0 overflow-visible lg:overflow-y-auto custom-scrollbar">
        <div className="flex justify-between items-start shrink-0">
          <div className="space-y-1">
            <h2 className="text-3xl font-black text-white tracking-tighter uppercase italic">FLOW CONTROL</h2>
            <div className="flex flex-wrap gap-1.5 mt-2">
               {[0, 1, 2, 3].map(n => (
                 <button key={n} onClick={() => handlePreset(n)} className={`w-9 h-9 rounded-lg border font-black text-[10px] transition-all ${n === 0 ? 'bg-white/5 border-white/10 text-gray-500' : 'bg-cyan-950/20 border-cyan-500/30 text-cyan-400 hover:bg-cyan-500 hover:text-black'}`}>
                   {n === 0 ? 'CLR' : `P${n}`}
                 </button>
               ))}
               <button onClick={() => handleSyncFromWheel('full')} className="px-3 h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 1</button>
               <button onClick={() => handleSyncFromWheel('title')} className="px-3 h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 2</button>
            </div>
          </div>
          <button onClick={onClose} className="p-3 rounded-2xl bg-white/5 text-gray-400 hover:text-white transition-all hover:bg-white/10 shrink-0">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="flex-1 space-y-4 pr-1">
          {labels.map((label, idx) => {
            let mappedNodeId = -1;
            for(let ni=0; ni<12; ni++) {
              if(getDisplayIdx(ni, labelOffset, activeMode) === idx) {
                mappedNodeId = ni + 1;
                break;
              }
            }
            const isCurrentlyActive = highlightedNodes.includes(mappedNodeId);

            return (
              <div key={idx} className={`group relative p-0.5 transition-all duration-300 ${isCurrentlyActive ? 'scale-[1.02]' : ''}`}>
                <div className="flex justify-between items-end mb-1 px-1">
                  <label className="text-[9px] text-gray-500 uppercase tracking-widest font-black block">Leaf {idx + 1}</label>
                  <span className={`text-[8px] font-mono px-1.5 py-0.5 rounded border transition-colors ${isCurrentlyActive ? 'bg-cyan-500/20 border-cyan-500 text-cyan-200' : 'bg-white/5 border-white/10 text-gray-600'}`}>
                    NODE: {mappedNodeId}
                  </span>
                </div>
                <input 
                  type="text" value={label} onChange={(e) => updateLabel(idx, e.target.value)} placeholder={`Terminal input ${idx + 1}...`}
                  className={`w-full bg-white/5 border rounded-xl px-4 py-3 text-sm font-medium focus:bg-cyan-950/10 outline-none transition-all placeholder-gray-800 ${isCurrentlyActive ? 'border-cyan-500/50 text-white' : 'border-white/5 text-cyan-50/70'}`}
                />
              </div>
            );
          })}
        </div>

        <div className="pt-6 border-t border-white/5 space-y-4 shrink-0 pb-6 bg-black/20 -mx-8 px-8">
          <div className="flex justify-between items-baseline px-1">
            <h3 className="text-xs font-black text-gray-500 uppercase tracking-[0.2em]">SYSTEM NAVIGATION</h3>
            <span className="font-mono text-[11px] text-cyan-500 px-2 py-0.5 rounded bg-cyan-950/30">Phase: {labelOffset + 1}</span>
          </div>
          <div className="flex p-1 bg-white/5 rounded-2xl gap-1">
            <button onClick={() => { setActiveMode('linear'); setIsCycling(false); }} className={`flex-1 py-3 rounded-xl text-[10px] font-black tracking-widest transition-all ${activeMode === 'linear' ? 'bg-cyan-500 text-black shadow-lg shadow-cyan-500/20' : 'text-gray-400'}`}>LINEAR</button>
            <button onClick={() => { setActiveMode('bifurcation'); setIsCycling(false); }} className={`flex-1 py-3 rounded-xl text-[10px] font-black tracking-widest transition-all ${activeMode === 'bifurcation' ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-600/20' : 'text-gray-400'}`}>BIFURCATE</button>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => handleShift('down')} className="bg-white/5 hover:bg-cyan-500/10 py-4 rounded-2xl border border-white/5 text-[10px] font-black tracking-widest transition-all uppercase">Prev Step</button>
            <button onClick={() => handleShift('up')} className="bg-white/5 hover:bg-cyan-500/10 py-4 rounded-2xl border border-white/5 text-[10px] font-black tracking-widest transition-all uppercase">Next Step</button>
          </div>
          <button onClick={() => setIsCycling(!isCycling)} className={`w-full py-4 rounded-2xl border font-black text-[11px] tracking-[0.2em] transition-all uppercase ${isCycling ? 'bg-red-600 text-white shadow-xl' : 'bg-cyan-600/10 text-cyan-400 border-cyan-500/20 hover:border-cyan-500/50'}`}>
            {isCycling ? 'Stop Stream' : `Animate Stream`}
          </button>
        </div>
      </aside>

      <div className="flex-1 h-[70vh] lg:h-full flex items-center justify-center p-4 lg:p-12">
        <div className="w-full h-full max-w-5xl max-h-screen flex items-center justify-center">
          {renderDiagram()}
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(6, 182, 212, 0.15); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(6, 182, 212, 0.3); }
      `}</style>
    </div>
  );
};

export default TreeOfLifeMode;

import React, { useMemo, useState, useEffect, useRef, useLayoutEffect } from 'react';
import { createPortal } from 'react-dom';
import * as d3 from 'd3';
import { KATHARA_CLOCK_POINTS, KATHARA_GRID_NODES, KATHARA_GRID_LINES, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, MUQATTAT_LETTERS, SLICE_DATA, ZAKKUM_CONFIG, DATE_PALM_CONFIG } from '../constants.ts';
import { getSliceAtPoint, colorScale, getChapterIcon } from '../utils.ts';
import { PlaylistType, SliceData, ChapterDetails } from '../types.ts';
import PlaylistButtons from './PlaylistButtons.tsx';
import { LoadSequenceIcon } from './Icons.tsx';

interface AlignmentProps {
    rotation: number;
    createPlaylist: (type: PlaylistType, chapterIds: number[]) => void;
    setCustomSequence: (value: string) => void;
    setAnimationMode: (mode: 'play' | 'step' | 'off') => void;
}

interface BaseChapterData {
    slice: SliceData;
    chapterInfo: ChapterDetails;
    isMuqattat: boolean;
    muqattatLetters: string[] | undefined;
    iconSrc: string;
}

interface AlignedChapter extends BaseChapterData {
    clockIndex: number;
    clockLabel: string;
    subLabel?: string;
    nodeColor?: string;
}

interface StaticChapter extends BaseChapterData {
    staticLabel: string;
    staticEmoji: string;
    staticRightText?: string;
    contentEmoji?: string;
    isStatic: true;
}

type DisplayChapter = AlignedChapter | StaticChapter;

// Shared hook for responsive portal positioning logic
const useDiagramPortal = (listRef: React.RefObject<HTMLDivElement>) => {
    const [isDesktop, setIsDesktop] = useState(typeof window !== 'undefined' ? window.innerWidth >= 1024 : false);
    const floatingRef = useRef<HTMLDivElement>(null);
    const portalRoot = typeof document !== 'undefined' ? document.getElementById('kathara-portal-root') : null;

    useEffect(() => {
        const handleResize = () => setIsDesktop(window.innerWidth >= 1024);
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    useLayoutEffect(() => {
        if (!isDesktop) return;

        let rafId: number;
        const updatePosition = () => {
            const listEl = listRef.current;
            const floatingEl = floatingRef.current;
            const scrollContainer = document.getElementById('side-panel-scroll-container');

            if (listEl && floatingEl && scrollContainer) {
                const listRect = listEl.getBoundingClientRect();
                const containerRect = scrollContainer.getBoundingClientRect();
                const diagramWidth = 240;
                const x = containerRect.left - diagramWidth + 12;
                const y = listRect.top;

                floatingEl.style.transform = `translate3d(${x}px, ${y}px, 0)`;
                floatingEl.style.height = `${listRect.height}px`;
                floatingEl.style.width = `${diagramWidth}px`;

                const isVisible = listRect.bottom > containerRect.top + 50 && listRect.top < containerRect.bottom - 50;
                floatingEl.style.opacity = isVisible ? '1' : '0';
            }
        };

        const loop = () => {
            updatePosition();
            rafId = requestAnimationFrame(loop);
        };

        rafId = requestAnimationFrame(loop);
        return () => cancelAnimationFrame(rafId);
    }, [isDesktop]);

    return { isDesktop, floatingRef, portalRoot };
};

export const KatharaClockAlignment: React.FC<AlignmentProps> = ({ rotation, createPlaylist, setCustomSequence, setAnimationMode }) => {
    const listRef = useRef<HTMLDivElement>(null);
    const { isDesktop, floatingRef, portalRoot } = useDiagramPortal(listRef);

    const alignedChapters: AlignedChapter[] = useMemo(() => {
        const labels = [
            'Awakening', 'Assertion', 'Disruption', 
            'Constriction', 'Refinement', 'Submission', 
            'Restoration', 'Servanthood', 'Sacrifice', 
            'Witness', 'Ascension', 'Radiance'
        ];
        return KATHARA_CLOCK_POINTS.map((pointValue, index) => {
            const slice = getSliceAtPoint(pointValue, rotation);
            const chapterInfo = CHAPTER_DETAILS[slice.id - 1];
            if (!chapterInfo) {
                // Fallback to prevent crash if index is somehow wrong
                return null;
            }
            return {
                slice,
                chapterInfo,
                isMuqattat: MUQATTAT_CHAPTERS.has(slice.id),
                muqattatLetters: MUQATTAT_LETTERS.get(slice.id),
                iconSrc: getChapterIcon(chapterInfo.revelationType),
                clockIndex: index + 1,
                clockLabel: labels[index]
            };
        }).filter((c): c is AlignedChapter => c !== null);
    }, [rotation]);

    const displayChapters: DisplayChapter[] = useMemo(() => {
        const chapters: DisplayChapter[] = [...alignedChapters];

        const getStaticChapterData = (id: number, label: string, bulletEmoji: string, contentEmoji?: string): StaticChapter | null => {
            const slice = SLICE_DATA.find(s => s.id === id);
            const chapterInfo = CHAPTER_DETAILS.find(c => c.number === id);
            if (!slice || !chapterInfo) return null;
             return {
                slice,
                chapterInfo,
                isMuqattat: MUQATTAT_CHAPTERS.has(slice.id),
                muqattatLetters: MUQATTAT_LETTERS.get(slice.id),
                iconSrc: getChapterIcon(chapterInfo.revelationType),
                staticLabel: label,
                staticEmoji: bulletEmoji,
                contentEmoji: contentEmoji,
                isStatic: true
            };
        };

        const static108 = getStaticChapterData(108, '⚡Promise', 'Nomination △');
        const static103 = getStaticChapterData(103, '🐟 Protection', 'Uproot 🔥');
        const static110 = getStaticChapterData(110, '🌳Return', 'Witness ⚫');
        const static112Start = getStaticChapterData(112, 'The Beginning ∞', '∞');
        const static112End = getStaticChapterData(112, 'Repeat ∞', '∞');

        if (static108) chapters.splice(3, 0, static108);
        if (static103) chapters.splice(7, 0, static103);
        if (static110) chapters.splice(11, 0, static110);

        const result: DisplayChapter[] = [];
        if (static112Start) result.push(static112Start);
        result.push(...chapters);
        if (static112End) result.push(static112End);

        return result;

    }, [alignedChapters]);

    const handleLoadKatharaSequence = () => {
        setAnimationMode('off');
        const chapterIds = displayChapters.map(c => c.slice.id);
        setCustomSequence(chapterIds.join(', '));
    };

    const handleWatchKatharaSequence = (type: PlaylistType) => {
        const chapterIds = displayChapters.slice(1).map(c => c.slice.id);
        createPlaylist(type, chapterIds);
    };

    const nodeMap = useMemo(() => new Map(KATHARA_GRID_NODES.map(node => [node.id, node])), []);

    const getVerticalWavePath = (x1: number, y1: number, x2: number, y2: number) => {
        const dy = y2 - y1;
        const amp = 7;
        return `M ${x1} ${y1} Q ${x1 + amp} ${y1 + dy * 0.125} ${x1} ${y1 + dy * 0.25} T ${x1} ${y1 + dy * 0.5} T ${x1} ${y1 + dy * 0.75} T ${x1} ${y2}`;
    };

    const renderDiagram = () => (
        <div className="flex justify-center w-full h-full">
            <svg viewBox="0 0 150 280" preserveAspectRatio={isDesktop ? "none" : "xMidYMid meet"} width="100%" height="100%" aria-hidden="true">
                <g strokeWidth="1.5">
                    {KATHARA_GRID_LINES.map((line, index) => {
                        const fromNode = nodeMap.get(line.from);
                        const toNode = nodeMap.get(line.to);
                        if (!fromNode || !toNode) return null;

                        let lineStyle: React.CSSProperties = { stroke: '#4b5563', filter: 'none' };
                        const f = line.from;

                        const isG1 = [1, 2, 3, 4, 13].includes(f);
                        const isG2 = [5, 6, 7, 14].includes(f);
                        const isG3 = [8, 9, 10, 15].includes(f);
                        const isG4 = [11, 12].includes(f);

                        if (isG1) lineStyle = { stroke: '#60a5fa', filter: 'drop-shadow(0 0 1.5px rgba(255, 255, 255, 0.6))' };
                        else if (isG2) lineStyle = { stroke: '#e2e8f0', filter: 'drop-shadow(0 0 1.5px rgba(249, 115, 22, 0.8))' };
                        else if (isG3) lineStyle = { stroke: '#fb923c', filter: 'drop-shadow(0 0 1.5px rgba(255, 255, 255, 0.6))' };
                        else if (isG4) lineStyle = { stroke: '#ffffff', filter: 'drop-shadow(0 0 1.5px rgba(74, 222, 128, 0.8))' };

                        const is112_1 = (line.from === 3 && line.to === 6) || (line.from === 6 && line.to === 3);
                        const is112_3 = (line.from === 6 && line.to === 9) || (line.from === 9 && line.to === 6);
                        const is112_4 = (line.from === 4 && line.to === 7) || (line.from === 7 && line.to === 4);
                        const is112_2 = (line.from === 7 && line.to === 10) || (line.from === 10 && line.to === 7);

                        let renderedLine;
                        if (is112_2) {
                            renderedLine = <path key={index} d={getVerticalWavePath(fromNode.x, fromNode.y, toNode.x, toNode.y)} fill="none" style={lineStyle} />;
                        } else if (is112_3 || is112_4) {
                            const dottedStyle = { ...lineStyle, strokeDasharray: '1 3', strokeLinecap: 'round' as const, strokeWidth: 2 };
                            renderedLine = <line key={index} x1={fromNode.x} y1={fromNode.y} x2={toNode.x} y2={toNode.y} style={dottedStyle} />;
                        } else {
                            renderedLine = <line key={index} x1={fromNode.x} y1={fromNode.y} x2={toNode.x} y2={toNode.y} style={lineStyle} />;
                        }

                        let label = null;
                        if (is112_1 || is112_2 || is112_3 || is112_4) {
                            const midX = (fromNode.x + toNode.x) / 2;
                            const midY = (fromNode.y + toNode.y) / 2;
                            const text = is112_1 ? "112:1" : is112_2 ? "112:2" : is112_3 ? "112:3" : "112:4";
                            const offsetX = (is112_1 || is112_3) ? -12 : 12;
                            const textX = midX + offsetX;
                            const textY = midY;

                            label = <text key={`label-${index}`} x={textX} y={textY} transform={`rotate(-90, ${textX}, ${textY})`} textAnchor="middle" dominantBaseline="middle" fontSize="7" fontWeight="bold" fill="#f0abfc" style={{ textShadow: '0 0 4px rgba(0,0,0,0.8)' }}>{text}</text>;
                        }

                        return <React.Fragment key={index}>{renderedLine}{label}</React.Fragment>;
                    })}
                </g>
                {KATHARA_GRID_NODES.map((node, index) => {
                    let label = '', staticContent = '', isStaticNode = false, fillColor = node.color, subLabel = '';
                    if (node.id > 12) {
                        isStaticNode = true;
                        if (node.shape === 'volcano') staticContent = '△108⚡';
                        if (node.shape === 'fish') staticContent = '🔥103🐟';
                        if (node.shape === 'palm') staticContent = '⚫110🌳';
                    } else {
                        const chapterData = alignedChapters.find(c => c.clockIndex === node.id);
                        if (chapterData) {
                            label = chapterData.slice.id.toString();
                            fillColor = colorScale(chapterData.slice.id);
                            subLabel = chapterData.clockLabel;
                        }
                    }
                    const textColor = d3.lab(fillColor).l < 60 ? 'white' : 'black';
                    return (
                        <g key={node.id}>
                            {isStaticNode ? (
                                <text x={node.x} y={node.y} textAnchor="middle" dominantBaseline="middle" fontSize="8" fontWeight="bold" fill="white" style={{ textShadow: '0 0 3px black', letterSpacing: '-0.5px' }}>{staticContent}</text>
                            ) : (
                                <g>
                                    <circle cx={node.x} cy={node.y} r={node.r} fill={fillColor} stroke="#1f2937" strokeWidth="0.5" />
                                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="8" fontWeight="bold" fill={textColor}>{label}</text>
                                    {subLabel && <text x={node.x} y={node.y + 13} textAnchor="middle" fontSize="4" fill="#94a3b8" fontWeight="normal" style={{ textShadow: '0 0 2px black' }}>{subLabel}</text>}
                                </g>
                            )}
                        </g>
                    );
                })}
            </svg>
        </div>
    );

    return (
        <div className="pt-4">
            <div className="flex justify-between items-center">
                <h2 className="text-xl font-bold text-gray-200 tracking-wider">🌳</h2>
                <div className="flex items-center space-x-2">
                    <button onClick={handleLoadKatharaSequence} className="bg-gray-600 hover:bg-cyan-700 text-white font-bold p-2 rounded transition-colors duration-200 flex-shrink-0" title="Load Tree of Life sequence into custom sequence">
                        <LoadSequenceIcon />
                    </button>
                    <PlaylistButtons onWatch={handleWatchKatharaSequence} />
                </div>
            </div>
            <div className="w-full h-px bg-gray-500/50 mt-2"></div>

            {!isDesktop ? (
                <div className="my-4 h-[420px]">{renderDiagram()}</div>
            ) : (
                portalRoot && createPortal(
                    <div ref={floatingRef} style={{ position: 'fixed', top: 0, left: 0, zIndex: 5, pointerEvents: 'none', opacity: 0, willChange: 'transform, height' }}>
                        {renderDiagram()}
                    </div>,
                    portalRoot
                )
            )}

            <div ref={listRef} className="text-sm text-gray-400 mt-3 space-y-1">
                {displayChapters.map((chapterData, index) => {
                    const chapterColor = colorScale(chapterData.slice.id);
                    const isStatic = 'isStatic' in chapterData;
                    let labelStyle = {};
                    let labelClass = "font-mono text-[10px] whitespace-nowrap overflow-hidden text-ellipsis tracking-tight";

                    if (isStatic) {
                        labelClass += " text-right pr-1 text-gray-500 tracking-tighter";
                    } else {
                        const idx = (chapterData as AlignedChapter).clockIndex;
                        if (idx >= 1 && idx <= 3) labelStyle = { color: '#60a5fa', textShadow: '0 0 5px rgba(255, 255, 255, 0.6)' };
                        else if (idx >= 4 && idx <= 6) labelStyle = { color: '#e2e8f0', textShadow: '0 0 5px rgba(249, 115, 22, 0.7)' };
                        else if (idx >= 7 && idx <= 9) labelStyle = { color: '#fb923c', textShadow: '0 0 5px rgba(255, 255, 255, 0.6)' };
                        else if (idx >= 10 && idx <= 12) labelStyle = { color: '#ffffff', textShadow: '0 0 5px rgba(74, 222, 128, 0.8)' };
                    }

                    return (
                        <div key={index} className={`grid grid-cols-[7rem_1fr] gap-x-1 items-center rounded px-2 py-1.5 transition-colors ${isStatic ? 'bg-gray-800/50 border border-gray-700/50' : 'hover:bg-white/5 border border-transparent'}`}>
                            <span className={labelClass} style={labelStyle}>
                                {isStatic ? (chapterData as StaticChapter).staticEmoji : `${(chapterData as AlignedChapter).clockIndex} ${(chapterData as AlignedChapter).clockLabel}:`}
                            </span>
                            <div className="flex items-center min-w-0">
                                <div className="w-5 flex-shrink-0 flex justify-center mr-1">
                                    <img src={chapterData.iconSrc} alt={chapterData.chapterInfo.revelationType} className="w-3.5 h-3.5" />
                                </div>
                                <div className="flex items-baseline min-w-0 flex-1 gap-x-2">
                                    <span className="truncate flex-1 flex items-center gap-1" title={`${chapterData.slice.id}: ${chapterData.chapterInfo.englishName}`} style={{ color: chapterColor }}>
                                        <span className={`font-semibold flex-shrink-0 ${chapterData.isMuqattat ? 'muqattat-glow' : ''}`}>
                                            {(isStatic && (chapterData as StaticChapter).contentEmoji) ? (chapterData as StaticChapter).contentEmoji : ''}{chapterData.slice.id}:
                                        </span>
                                        <span className="truncate">{isStatic ? (chapterData as StaticChapter).staticLabel : chapterData.chapterInfo.englishName}</span>
                                    </span>
                                    {chapterData.muqattatLetters && <span className="font-mono text-xs muqattat-glow flex-shrink-0 opacity-80" dir="rtl">{chapterData.muqattatLetters.join(' ')}</span>}
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

export const SephirotAlignment: React.FC<AlignmentProps> = ({ rotation, createPlaylist, setCustomSequence, setAnimationMode }) => {
    const [activeTab, setActiveTab] = useState<'zakkum' | 'datePalm'>('datePalm');
    const listRef = useRef<HTMLDivElement>(null);
    const { isDesktop, floatingRef, portalRoot } = useDiagramPortal(listRef);

    const currentConfig = activeTab === 'zakkum' ? ZAKKUM_CONFIG : DATE_PALM_CONFIG;

    const generatedChaptersMap = useMemo(() => {
        const standardNodes = currentConfig.nodes.filter(n => !n.isZero).sort((a,b) => a.id - b.id);
        const zeroNode = currentConfig.nodes.find(n => n.isZero);
        const map = new Map<number, AlignedChapter | StaticChapter>();

        standardNodes.forEach((node, index) => {
            const pointValue = currentConfig.points[index];
            const slice = getSliceAtPoint(pointValue, rotation);
            const chapterInfo = CHAPTER_DETAILS.find(c => c.number === slice.id);
            if (!chapterInfo) return;
            map.set(node.id, {
                slice,
                chapterInfo,
                isMuqattat: MUQATTAT_CHAPTERS.has(slice.id),
                muqattatLetters: MUQATTAT_LETTERS.get(slice.id),
                iconSrc: getChapterIcon(chapterInfo.revelationType),
                clockIndex: node.id,
                clockLabel: node.label,
                nodeColor: node.color
            });
        });

        if (zeroNode && currentConfig.point0) {
            const slice = getSliceAtPoint(currentConfig.point0, rotation);
            const chapterInfo = CHAPTER_DETAILS.find(c => c.number === slice.id);
            if (chapterInfo) {
              map.set(0, {
                  slice,
                  chapterInfo,
                  isMuqattat: MUQATTAT_CHAPTERS.has(slice.id),
                  muqattatLetters: MUQATTAT_LETTERS.get(slice.id),
                  iconSrc: getChapterIcon(chapterInfo.revelationType),
                  clockIndex: 0,
                  clockLabel: zeroNode.label,
                  nodeColor: zeroNode.color
              });
            }
        }
        return map;
    }, [rotation, currentConfig, activeTab]);

    const displayChapters: (AlignedChapter | StaticChapter)[] = useMemo(() => {
        const chapters: (AlignedChapter | StaticChapter)[] = [];
        const getStaticChapterData = (id: number, leftLabel: string, rightText: string, emoji: string): StaticChapter | null => {
            const slice = SLICE_DATA.find(s => s.id === id);
            const chapterInfo = CHAPTER_DETAILS.find(c => c.number === id);
            if (!slice || !chapterInfo) return null;
             return {
                slice,
                chapterInfo,
                isMuqattat: MUQATTAT_CHAPTERS.has(slice.id),
                muqattatLetters: MUQATTAT_LETTERS.get(slice.id),
                iconSrc: getChapterIcon(chapterInfo.revelationType),
                staticLabel: leftLabel,
                staticRightText: rightText,
                staticEmoji: emoji,
                isStatic: true
            };
        };

        if (activeTab === 'zakkum') {
            const static110 = getStaticChapterData(110, 'Beginning', 'Truth Always Wins (110)', '');
            const static103 = getStaticChapterData(103, 'Trial', 'Reflection (103)', '');
            const static108 = getStaticChapterData(108, 'Restoration', 'Bounty (108)', '');
            if (static110) chapters.push(static110);
            [6, 1, 9, 8, 7].forEach(id => { const c = generatedChaptersMap.get(id); if (c) chapters.push(c); });
            if (static103) chapters.push(static103);
            [0, 2, 3, 4, 5].forEach(id => { const c = generatedChaptersMap.get(id); if (c) chapters.push(c); });
            if (static108) chapters.push(static108);
        } else {
            const static108 = getStaticChapterData(108, 'Blessing', 'Bounty (108)', '');
            const static103 = getStaticChapterData(103, 'Patience', 'Time (103)', '');
            const static112 = getStaticChapterData(112, 'Emergence', 'The Absolute Truth (112)', '');
            if (static108) chapters.push(static108);
            [1, 2, 3, 4, 5].forEach(id => { const c = generatedChaptersMap.get(id); if (c) chapters.push(c); });
            if (static103) chapters.push(static103);
            [6, 7, 8, 9, 10].forEach(id => { const c = generatedChaptersMap.get(id); if (c) chapters.push(c); });
            if (static112) chapters.push(static112);
        }
        return chapters;
    }, [generatedChaptersMap, activeTab]);

    const handleLoadSequence = () => {
        setAnimationMode('off');
        const chapterIds = displayChapters.map(c => c.slice.id).filter(id => id > 0);
        setCustomSequence(chapterIds.join(', '));
    };

    const handleWatchSequence = (type: PlaylistType) => {
        const chapterIds = displayChapters.map(c => c.slice.id).filter(id => id > 0);
        createPlaylist(type, chapterIds);
    };

    const nodeMap = useMemo(() => new Map(currentConfig.nodes.map(node => [node.id, node] as [number, typeof node])), [currentConfig]);

    const renderDiagram = () => (
        <div className="flex justify-center w-full h-full">
            <svg viewBox="0 0 200 320" preserveAspectRatio={isDesktop ? "none" : "xMidYMid meet"} width="100%" height="100%" aria-hidden="true">
                <g strokeWidth="1.5">
                    {currentConfig.lines.map((line, index) => {
                        const fromNode = nodeMap.get(line.from);
                        const toNode = nodeMap.get(line.to);
                        if (!fromNode || !toNode) return null;
                        return <line key={index} x1={fromNode.x} y1={fromNode.y} x2={toNode.x} y2={toNode.y} stroke="#4b5563" style={{ stroke: activeTab === 'datePalm' ? '#60a5fa' : '#ef4444', opacity: 0.5 }} />;
                    })}
                </g>
                {currentConfig.nodes.map((node, index) => {
                    let label = '', fillColor = node.color;
                    const chapterData = generatedChaptersMap.get(node.id);
                    if (chapterData && !('isStatic' in chapterData)) label = (chapterData as AlignedChapter).slice.id.toString();
                    else if (node.isZero && activeTab === 'datePalm') label = '∞';
                    const textColor = d3.lab(fillColor).l < 60 ? 'white' : 'black';
                    return (
                        <g key={node.id}>
                            <circle cx={node.x} cy={node.y} r={10} fill={fillColor} stroke="#1f2937" strokeWidth="1" />
                            <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="8" fontWeight="bold" fill={textColor}>{label}</text>
                            <text x={node.x} y={node.y - 14} textAnchor="middle" fontSize="7" fontWeight="bold" fill={fillColor} style={{ textShadow: '0 0 3px black' }}>{node.label}</text>
                        </g>
                    );
                })}
            </svg>
        </div>
    );

    return (
        <div className="pt-6">
            <div className="flex justify-between items-center">
                <h2 className="text-xl font-bold text-gray-200 tracking-wider">Sephirot Alignment</h2>
                <div className="flex items-center space-x-2">
                    <button onClick={handleLoadSequence} className="bg-gray-600 hover:bg-cyan-700 text-white font-bold p-2 rounded transition-colors duration-200 flex-shrink-0" title="Load current sequence into custom sequence">
                        <LoadSequenceIcon />
                    </button>
                    <PlaylistButtons onWatch={handleWatchSequence} />
                </div>
            </div>
            <div className="flex space-x-1 mt-3 mb-2 bg-gray-900/50 p-1 rounded-lg">
                <button onClick={() => setActiveTab('zakkum')} className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-colors ${activeTab === 'zakkum' ? 'bg-red-900/50 text-red-200 shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>Zakkum (Left)</button>
                <button onClick={() => setActiveTab('datePalm')} className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-colors ${activeTab === 'datePalm' ? 'bg-emerald-900/50 text-emerald-200 shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>Date-Palm (Right)</button>
            </div>
            <div className="w-full h-px bg-gray-500/50 mb-2"></div>

            {!isDesktop ? (
                <div className="my-4 h-[420px]">{renderDiagram()}</div>
            ) : (
                portalRoot && createPortal(
                    <div ref={floatingRef} style={{ position: 'fixed', top: 0, left: 0, zIndex: 5, pointerEvents: 'none', opacity: 0, willChange: 'transform, height' }}>
                        {renderDiagram()}
                    </div>,
                    portalRoot
                )
            )}

            <div ref={listRef} className="text-sm text-gray-400 mt-3 space-y-1">
                {displayChapters.map((chapterData, index) => {
                    if ('isStatic' in chapterData) {
                        const staticC = chapterData as StaticChapter;
                        const chapterColor = colorScale(staticC.slice.id);
                        return (
                        <div key={index} className="grid grid-cols-[5.5rem_1fr] gap-x-2 items-center bg-gray-800/50 rounded px-2 py-1.5 transition-colors border border-gray-700/50 mt-2">
                            <div className="flex flex-col items-end pr-2 border-r border-gray-700/50">
                                <span className="font-mono text-[10px] text-cyan-400 font-bold tracking-tighter shadow-cyan-500/20 drop-shadow-sm truncate whitespace-nowrap">{staticC.staticEmoji ? `${staticC.staticEmoji}. ` : ''}{staticC.staticLabel}</span>
                            </div>
                            <div className="flex items-center min-w-0 pl-1">
                                {staticC.staticRightText ? (
                                    <span className="truncate font-semibold text-sm" style={{ color: chapterColor }}>{staticC.staticRightText}</span>
                                ) : (
                                    <div className="flex items-center gap-1">
                                        <img src={staticC.iconSrc} alt={staticC.chapterInfo.revelationType} className="w-3 h-3" />
                                        <span className="truncate font-semibold text-sm" style={{ color: chapterColor }}>{staticC.slice.id}: {staticC.chapterInfo.englishName}</span>
                                    </div>
                                )}
                            </div>
                        </div>
                        )
                    }
                    const cData = chapterData as AlignedChapter;
                    const chapterColor = colorScale(cData.slice.id);
                    return (
                        <div key={index} className="grid grid-cols-[5.5rem_1fr] gap-x-2 items-center hover:bg-white/5 rounded px-2 py-2 transition-colors border border-transparent">
                            <div className="flex flex-col items-end pr-2 border-r border-gray-700/50">
                                <span className="font-mono text-sm font-bold tracking-tight whitespace-nowrap" style={{ color: cData.nodeColor }}>{cData.clockIndex}. {cData.clockLabel}</span>
                            </div>
                            <div className="flex items-center min-w-0 pl-1">
                                <div className="flex flex-col min-w-0">
                                    <div className="flex items-baseline min-w-0 gap-x-1.5">
                                        <img src={cData.iconSrc} alt={cData.chapterInfo.revelationType} className="w-3 h-3 flex-shrink-0 self-center" />
                                        <span className="truncate text-sm font-medium" title={`${cData.slice.id}: ${cData.chapterInfo.englishName}`} style={{ color: chapterColor }}>
                                            <span className={`font-bold mr-1 ${cData.isMuqattat ? 'muqattat-glow' : ''}`}>{cData.slice.id}:</span>{cData.chapterInfo.englishName}
                                        </span>
                                        {cData.muqattatLetters && <span className="font-mono text-[10px] muqattat-glow flex-shrink-0 opacity-80" dir="rtl">{cData.muqattatLetters.join(' ')}</span>}
                                    </div>
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

export default SephirotAlignment;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { KATHARA_GRID_NODES, KATHARA_GRID_LINES, KATHARA_CLOCK_POINTS, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, MUQATTAT_LETTERS } from '../constants.ts';
import { getSliceAtPoint } from '../utils.ts';

interface TreeOfLifeModeProps {
  rotation: number;
  onClose: () => void;
}

const PRESET_1 = [
  "Book", "Chosen One | Rasul", "Sign", "Prophet", "Challenge | Rescue", "Curse", 
  "Blessed Land", "Believer | Servant", "Suhuf", "Teacher", "Witness | Driver", "Stone"
];

const PRESET_2 = [
  "Ibrahim | Yahya",
  "Rushd",
  "Challenge",
  "Destroy",
  "Witness",
  "Battle | Pit",
  "Solomon | Musa",
  "Zabur",
  "Dawud",
  "High Ground",
  "Palm Date Tree",
  "Action | Word"
];

const PRESET_3 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Rushd",
  "Stone",
  "Iron | Wood",
  "Noah | Musa",
  "Idris | Isa",
  "Iron | Mountain",
  "Amanah",
  "Dawud",
  "Solomon | Death",
  "Book | Yahya"
];

interface BifurcationStage {
  main: number[];
  manualLines: [number, number][];
  isBlackPhase?: boolean;
}

const TreeOfLifeMode: React.FC<TreeOfLifeModeProps> = ({ rotation, onClose }) => {
  const [labels, setLabels] = useState<string[]>(Array(12).fill(''));
  const [labelOffset, setLabelOffset] = useState(0); 
  const [isCycling, setIsCycling] = useState(false);
  const [activeMode, setActiveMode] = useState<'linear' | 'bifurcation'>('linear');
  const [highlightedNodes, setHighlightedNodes] = useState<number[]>([]);

  const [showLightning, setShowLightning] = useState(false);
  const [showExplosion, setShowExplosion] = useState(false);

  // Domain Node Sets
  const BLUE_NODES = [1, 2, 3, 4, 5, 6, 13];
  const GREEN_NODES = [12, 11, 10, 9, 8, 7, 15];

  const LOOP_LINES: [number, number][] = [[2, 3], [3, 6], [6, 9], [9, 11], [11, 10], [10, 7], [7, 4], [4, 2]];
  const BOLT_3_10_LINES: [number, number][] = [[3, 13], [4, 13], [4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9], [9, 15], [10, 15]];
  const BOLT_4_9_LINES: [number, number][] = [[4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9]];
  const PATH_5_8_LINES: [number, number][] = [[5, 6], [6, 14], [7, 14], [7, 8]];
  const CROSS_PLUS_LINES: [number, number][] = [[6, 14], [7, 14], [5, 14], [14, 8], [6, 7], [5, 8]];

  const DUAL_GROUP_LINES: [number, number][] = [
    [1, 2], [2, 3], [2, 4], [2, 13], [3, 13], [4, 13], [3, 5], [4, 5], [5, 6], [3, 6], [13, 5],
    [12, 11], [11, 10], [11, 9], [9, 15], [10, 15], [15, 8], [8, 9], [8, 10], [7, 8], [7, 10], [15, 11]
  ];
  const SQUARE_PLUS_LINES: [number, number][] = [[5, 6], [5, 7], [6, 8], [7, 8], [6, 14], [14, 7], [5, 14], [14, 8]];

  const BIFURCATION_STAGES: BifurcationStage[] = useMemo(() => [
    { main: [1, 12], manualLines: [], isBlackPhase: true },
    { main: [2, 11], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: CROSS_PLUS_LINES },
    { main: [12, 1], manualLines: DUAL_GROUP_LINES },
    { main: [11, 2], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: SQUARE_PLUS_LINES },
  ], []);

  const handleSyncFromWheel = (mode: 'full' | 'title') => {
    const newLabels = KATHARA_CLOCK_POINTS.map(pointValue => {
        const slice = getSliceAtPoint(pointValue, rotation);
        const chapterInfo = CHAPTER_DETAILS.find(c => c.number === slice.id);
        const title = chapterInfo?.englishName || 'Unknown';
        const letters = MUQATTAT_LETTERS.get(slice.id)?.join(' ') || '';
        if (mode === 'title') return `${title}${letters ? ` | ${letters}` : ''}`;
        return `${slice.id} ${title}${letters ? ` | ${letters}` : ''}`;
    });
    setLabels(newLabels);
    setLabelOffset(0);
  };

  const handlePreset = (num: number) => {
    setLabelOffset(0);
    setHighlightedNodes([]);
    setIsCycling(false);
    if (num === 0) setLabels(Array(12).fill(''));
    else if (num === 1) setLabels([...PRESET_1]);
    else if (num === 2) setLabels([...PRESET_2]);
    else if (num === 3) setLabels([...PRESET_3]);
  };

  const updateVisuals = useCallback((offset: number) => {
    if (activeMode === 'linear') setHighlightedNodes([offset + 1]);
    else setHighlightedNodes(BIFURCATION_STAGES[offset].main);
  }, [activeMode, BIFURCATION_STAGES]);

  const handleShift = useCallback((direction: 'up' | 'down') => {
    setLabelOffset((prev) => {
      const next = direction === 'up' ? (prev + 1) % 12 : (prev - 1 + 12) % 12;
      if (activeMode === 'bifurcation') {
        if (prev === 11 && next === 0) { setShowLightning(true); setTimeout(() => setShowLightning(false), 800); }
        if (prev === 5 && next === 6) { setShowExplosion(true); setTimeout(() => setShowExplosion(false), 1200); }
      }
      updateVisuals(next);
      return next;
    });
  }, [updateVisuals, activeMode]);

  useEffect(() => { updateVisuals(labelOffset); }, [activeMode, updateVisuals, labelOffset]);

  useEffect(() => {
    if (!isCycling) return;
    const intervalId = window.setInterval(() => { handleShift('up'); }, 1800);
    return () => clearInterval(intervalId);
  }, [isCycling, handleShift]);

  const updateLabel = (index: number, val: string) => {
    const next = [...labels];
    next[index] = val;
    setLabels(next);
  };

  const getLineStatus = useCallback((from: number, to: number, h: number[], offset: number) => {
    if (activeMode === 'linear') {
      const nodeId = h[0];
      return from === nodeId || to === nodeId ? 'main' : null;
    }
    const stage = BIFURCATION_STAGES[offset];
    if (stage.isBlackPhase) return 'black';
    const isManual = stage.manualLines?.some(l => (l[0] === from && l[1] === to) || (l[0] === to && l[1] === from));
    return isManual ? 'main' : null;
  }, [activeMode, BIFURCATION_STAGES]);

  const getDisplayIdx = useCallback((nodeIdx: number, offset: number, mode: 'linear' | 'bifurcation') => {
    if (mode === 'linear') return (nodeIdx - offset + 12) % 12;
    const step = offset % 6;
    const hasCrossed = offset >= 6;
    if (nodeIdx < 6) return hasCrossed ? (nodeIdx - step + 6) % 6 + 6 : (nodeIdx - step + 6) % 6;
    return hasCrossed ? (11 - nodeIdx - step + 6) % 6 : (11 - nodeIdx - step + 6) % 6 + 6;
  }, []);

  const renderDiagram = () => {
    const isPhase2or8 = activeMode === 'bifurcation' && (labelOffset === 1 || labelOffset === 7);
    const extraSilverLines = isPhase2or8 ? [[9, 7], [6, 4]] : [];

    return (
      <div className="relative flex items-center justify-center bg-black/80 overflow-hidden h-full w-full rounded-3xl lg:rounded-none">
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[90%] h-[90%] rounded-full bg-cyan-950/10 blur-[120px] lg:blur-[180px]"></div>
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000_100%)] opacity-80"></div>
        </div>

        <style>{`
          .node-glow { filter: drop-shadow(0 0 15px currentColor); }
          .kathara-svg { width: 100%; height: 100%; max-height: 85vh; padding: 20px; }
          .junction-box { stroke-width: 1; fill: rgba(0, 0, 0, 0.85); stroke: rgba(255, 255, 255, 0.1); }
          .active-junction { stroke: #fff; stroke-width: 1.5; fill: rgba(8, 145, 178, 0.3); }
          .filter-junction { stroke: #06b6d4; fill: rgba(0, 30, 40, 0.9); }

          @keyframes flow-up { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }
          @keyframes flow-down { 0% { stroke-dashoffset: 0; } 100% { stroke-dashoffset: 40; } }
          @keyframes flow-silver { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }

          .liquid-blue-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-up 1.6s linear infinite; filter: drop-shadow(0 0 6px #06b6d4); }
          .liquid-green-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-down 1.6s linear infinite; filter: drop-shadow(0 0 6px #4ade80); }
          .liquid-silver-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-silver 1.6s linear infinite; filter: drop-shadow(0 0 6px #cbd5e1); }

          @keyframes spark { 0%, 100% { opacity: 0; stroke-width: 1; } 20% { opacity: 1; stroke-width: 4; } 60% { opacity: 1; stroke-width: 2; } }
          .lightning-bolt { stroke: #fff; filter: drop-shadow(0 0 12px cyan); animation: spark 0.25s infinite; }

          @keyframes blast { 0% { transform: scale(0); opacity: 1; filter: blur(0px); } 50% { transform: scale(3); opacity: 0.5; filter: blur(5px); } 100% { transform: scale(4.5); opacity: 0; filter: blur(10px); } }
          .fire-burst { fill: #f97316; animation: blast 0.8s ease-out forwards; }
        `}</style>

        <svg viewBox="-70 0 290 280" className="kathara-svg drop-shadow-[0_0_80px_rgba(6,182,212,0.15)]">
          <defs>
            <linearGradient id="activeGrad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#0891b2" />
              <stop offset="100%" stopColor="#06b6d4" />
            </linearGradient>
          </defs>

          <g>
            {KATHARA_GRID_LINES.map((line, index) => {
              const fromNode = KATHARA_GRID_NODES.find(n => n.id === line.from);
              const toNode = KATHARA_GRID_NODES.find(n => n.id === line.to);
              if (!fromNode || !toNode) return null;

              const status = getLineStatus(line.from, line.to, highlightedNodes, labelOffset);
              const isMain = status === 'main';
              const isAscending = fromNode.y > toNode.y;

              const isBlueDomain = (BLUE_NODES.includes(line.from) && BLUE_NODES.includes(line.to)) || 
                                  ((line.from === 14 || line.to === 14) && (BLUE_NODES.includes(line.from) || BLUE_NODES.includes(line.to)));

              const isGreenDomain = (GREEN_NODES.includes(line.from) && GREEN_NODES.includes(line.to)) || 
                                   ((line.from === 14 || line.to === 14) && (GREEN_NODES.includes(line.from) || GREEN_NODES.includes(line.to)));

              const isPhase12 = activeMode === 'bifurcation' && labelOffset === 11;
              const isSilverLine = isPhase12 && (
                (line.from === 6 && line.to === 8) || (line.from === 8 && line.to === 6) ||
                (line.from === 8 && line.to === 7) || (line.from === 7 && line.to === 8) ||
                (line.from === 7 && line.to === 5) || (line.from === 5 && line.to === 7) ||
                (line.from === 5 && line.to === 6) || (line.from === 6 && line.to === 5)
              );

              const showBlue = activeMode === 'linear' ? isMain : (isMain && isBlueDomain && !isSilverLine);
              const showGreen = activeMode === 'linear' ? isMain : (isMain && isGreenDomain && !isSilverLine);
              const showSilver = isMain && isSilverLine;

              const dx = toNode.x - fromNode.x;
              const dy = toNode.y - fromNode.y;
              const len = Math.sqrt(dx*dx + dy*dy);
              const nx = -dy / (len || 1);
              const ny = dx / (len || 1);
              const offsetDist = activeMode === 'linear' ? 2.0 : 0;

              return (
                <g key={index}>
                  <line 
                    x1={fromNode.x} y1={fromNode.y} 
                    x2={toNode.x} y2={toNode.y} 
                    stroke={isMain ? (isSilverLine ? "rgba(203,213,225,0.2)" : "rgba(255,255,255,0.12)") : status === 'black' ? "#0a0a0a" : "rgba(255,255,255,0.04)"}
                    strokeWidth={isMain ? 4 : 1}
                    className="transition-all duration-700"
                  />
                  {showBlue && <line x1={(isAscending ? fromNode.x : toNode.x) + nx * offsetDist} y1={(isAscending ? fromNode.y : toNode.y) + ny * offsetDist} x2={(isAscending ? toNode.x : fromNode.x) + nx * offsetDist} y2={(isAscending ? toNode.y : fromNode.y) + ny * offsetDist} stroke="#06b6d4" strokeWidth="3.5" className="liquid-blue-flow" />}
                  {showGreen && <line x1={(isAscending ? toNode.x : fromNode.x) - nx * offsetDist} y1={(isAscending ? toNode.y : fromNode.y) - ny * offsetDist} x2={(isAscending ? fromNode.x : toNode.x) - nx * offsetDist} y2={(isAscending ? fromNode.y : toNode.y) - ny * offsetDist} stroke="#4ade80" strokeWidth="3.5" className="liquid-green-flow" />}
                  {showSilver && <line x1={fromNode.x} y1={fromNode.y} x2={toNode.x} y2={toNode.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />}
                </g>
              );
            })}
            {extraSilverLines.map(([fromId, toId], idx) => {
              const f = KATHARA_GRID_NODES.find(n => n.id === fromId);
              const t = KATHARA_GRID_NODES.find(n => n.id === toId);
              if (!f || !t) return null;
              return (
                <g key={`extra-silver-${idx}`}>
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="rgba(203,213,225,0.4)" strokeWidth="3" />
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />
                </g>
              );
            })}
          </g>

          {showLightning && (
            <g className="pointer-events-none">
              <path d="M 75 20 L 95 60 L 55 100 L 75 140" fill="none" className="lightning-bolt" />
              <path d="M 30 140 L 55 170 L 35 200 L 75 240" fill="none" className="lightning-bolt" />
              <path d="M 120 140 L 95 170 L 115 200 L 75 240" fill="none" className="lightning-bolt" />
            </g>
          )}

          {showExplosion && (
            <g transform="translate(75, 140)" className="pointer-events-none">
              <circle r="12" className="fire-burst" />
              <circle r="8" className="fire-burst" style={{ animationDelay: '0.1s' }} />
            </g>
          )}

          {KATHARA_GRID_NODES.map((node, nodeIdx) => {
            const isFilter = node.id > 12;
            const isHighlighted = highlightedNodes.includes(node.id);
            const displayLabelIdx = isFilter ? -1 : getDisplayIdx(nodeIdx, labelOffset, activeMode);
            const rawLabel = isFilter ? '' : labels[displayLabelIdx];

            // Combined triplet labels as requested
            const filterFullLabel = node.id === 13 ? '△108⚡' : node.id === 14 ? '🔥103🐟' : node.id === 15 ? '⚫110🌳' : null;

            const labelParts = rawLabel ? rawLabel.split('|').map(p => p.trim()) : [];
            const hasMultiple = labelParts.length > 1;
            const isSpineNode = node.x === 75 && node.id <= 12; 
            const isLeftSide = node.x < 75;

            return (
              <g key={node.id} className="transition-all duration-500">
                {isFilter ? (
                  <g>
                    {isHighlighted && <rect x={node.x-28} y={node.y-12} width="56" height="24" rx="4" fill="rgba(6,182,212,0.15)" className="animate-pulse" />}
                    <rect x={node.x-25} y={node.y-10} width="50" height="20" rx="3" className={`filter-junction ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#06b6d4' }} />
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".35em" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#0891b2"} className="font-mono tracking-tighter" style={{ pointerEvents: 'none' }}>
                      {filterFullLabel}
                    </text>
                  </g>
                ) : (
                  <g>
                    <rect x={node.x-14} y={node.y-14} width="28" height="28" rx="6" className={`junction-box ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#fff' }} />
                    {isHighlighted && <circle cx={node.x} cy={node.y} r={22} fill="url(#activeGrad)" opacity="0.1" className="animate-pulse" />}
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".35em" fontSize="8" fontWeight="black" fill={isHighlighted ? "#fff" : "#555"}>{node.id}</text>
                    {rawLabel && (
                      <g className="pointer-events-none">
                         {isSpineNode && hasMultiple ? (
                          <>
                            <rect x={node.x - 76} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x - 22} y={node.y} textAnchor="end" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[0]}</text>
                            <rect x={node.x + 18} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x + 22} y={node.y} textAnchor="start" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[1]}</text>
                          </>
                         ) : (
                          <g>
                             <rect x={isLeftSide ? node.x - 76 : node.x + 18} y={node.y - (hasMultiple ? 14 : 9)} width="58" height={hasMultiple ? 28 : 18} rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                             <text x={isLeftSide ? node.x - 22 : node.x + 22} y={node.y} textAnchor={isLeftSide ? "end" : "start"} dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">
                               {hasMultiple ? (<><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="-0.5em">{labelParts[0]}</tspan><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="1.1em">{labelParts[1]}</tspan></>) : rawLabel}
                             </text>
                          </g>
                         )}
                      </g>
                    )}
                  </g>
                )}
              </g>
            );
          })}
        </svg>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#02040a] animate-in fade-in zoom-in duration-500 overflow-y-auto lg:overflow-hidden">
      <aside className="w-full lg:w-[420px] h-fit lg:h-full p-8 border-b lg:border-r border-white/10 flex flex-col space-y-6 bg-black/40 backdrop-blur-xl shrink-0 overflow-visible lg:overflow-y-auto custom-scrollbar">
        <div className="flex justify-between items-start shrink-0">
          <div className="space-y-1">
            <h2 className="text-2xl font-black text-white tracking-tighter uppercase italic leading-tight">
              Photosynthesis:
              <span className="block text-xs md:text-sm font-bold tracking-widest text-cyan-400 mt-1 not-italic">
                Harvesting Love and Intelligence in Form
              </span>
            </h2>
            <div className="flex flex-wrap gap-1.5 mt-2">
               {[0, 1, 2, 3].map(n => (
                 <button key={n} onClick={() => handlePreset(n)} className={`w-9 h-9 rounded-lg border font-black text-[10px] transition-all ${n === 0 ? 'bg-white/5 border-white/10 text-gray-500' : 'bg-cyan-950/20 border-cyan-500/30 text-cyan-400 hover:bg-cyan-500 hover:text-black'}`}>
                   {n === 0 ? 'CLR' : `P${n}`}
                 </button>
               ))}
               <button onClick={() => handleSyncFromWheel('full')} className="px-3 h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 1</button>
               <button onClick={() => handleSyncFromWheel('title')} className="px-3 h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 2</button>
            </div>
          </div>
          <button onClick={onClose} className="p-3 rounded-2xl bg-white/5 text-gray-400 hover:text-white transition-all hover:bg-white/10 shrink-0">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="flex-1 space-y-4 pr-1">
          {labels.map((label, idx) => {
            let mappedNodeId = -1;
            for(let ni=0; ni<12; ni++) {
              if(getDisplayIdx(ni, labelOffset, activeMode) === idx) {
                mappedNodeId = ni + 1;
                break;
              }
            }
            const isCurrentlyActive = highlightedNodes.includes(mappedNodeId);

            return (
              <div key={idx} className={`group relative p-0.5 transition-all duration-300 ${isCurrentlyActive ? 'scale-[1.02]' : ''}`}>
                <div className="flex justify-between items-end mb-1 px-1">
                  <label className="text-[9px] text-gray-500 uppercase tracking-widest font-black block">Leaf {idx + 1}</label>
                  <span className={`text-[8px] font-mono px-1.5 py-0.5 rounded border transition-colors ${isCurrentlyActive ? 'bg-cyan-500/20 border-cyan-500 text-cyan-200' : 'bg-white/5 border-white/10 text-gray-600'}`}>
                    NODE: {mappedNodeId}
                  </span>
                </div>
                <input 
                  type="text" value={label} onChange={(e) => updateLabel(idx, e.target.value)} placeholder={`Terminal input ${idx + 1}...`}
                  className={`w-full bg-white/5 border rounded-xl px-4 py-3 text-sm font-medium focus:bg-cyan-950/10 outline-none transition-all placeholder-gray-800 ${isCurrentlyActive ? 'border-cyan-500/50 text-white' : 'border-white/5 text-cyan-50/70'}`}
                />
              </div>
            );
          })}
        </div>

        <div className="pt-6 border-t border-white/5 space-y-4 shrink-0 pb-6 bg-black/20 -mx-8 px-8">
          <div className="flex justify-between items-baseline px-1">
            <h3 className="text-xs font-black text-gray-500 uppercase tracking-[0.2em]">SYSTEM NAVIGATION</h3>
            <span className="font-mono text-[11px] text-cyan-500 px-2 py-0.5 rounded bg-cyan-950/30">Phase: {labelOffset + 1}</span>
          </div>
          <div className="flex p-1 bg-white/5 rounded-2xl gap-1">
            <button onClick={() => { setActiveMode('linear'); setIsCycling(false); }} className={`flex-1 py-3 rounded-xl text-[10px] font-black tracking-widest transition-all ${activeMode === 'linear' ? 'bg-cyan-500 text-black shadow-lg shadow-cyan-500/20' : 'text-gray-400'}`}>LINEAR</button>
            <button onClick={() => { setActiveMode('bifurcation'); setIsCycling(false); }} className={`flex-1 py-3 rounded-xl text-[10px] font-black tracking-widest transition-all ${activeMode === 'bifurcation' ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-600/20' : 'text-gray-400'}`}>BIFURCATE</button>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => handleShift('down')} className="bg-white/5 hover:bg-cyan-500/10 py-4 rounded-2xl border border-white/5 text-[10px] font-black tracking-widest transition-all uppercase">Prev Step</button>
            <button onClick={() => handleShift('up')} className="bg-white/5 hover:bg-cyan-500/10 py-4 rounded-2xl border border-white/5 text-[10px] font-black tracking-widest transition-all uppercase">Next Step</button>
          </div>
          <button onClick={() => setIsCycling(!isCycling)} className={`w-full py-4 rounded-2xl border font-black text-[11px] tracking-[0.2em] transition-all uppercase ${isCycling ? 'bg-red-600 text-white shadow-xl' : 'bg-cyan-600/10 text-cyan-400 border-cyan-500/20 hover:border-cyan-500/50'}`}>
            {isCycling ? 'Stop Stream' : `Animate Stream`}
          </button>
        </div>
      </aside>

      <div className="flex-1 h-[70vh] lg:h-full flex items-center justify-center p-4 lg:p-12">
        <div className="w-full h-full max-w-5xl max-h-screen flex items-center justify-center">
          {renderDiagram()}
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(6, 182, 212, 0.15); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(6, 182, 212, 0.3); }
      `}</style>
    </div>
  );
};

export default TreeOfLifeMode;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { KATHARA_GRID_NODES, KATHARA_GRID_LINES, KATHARA_CLOCK_POINTS, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, MUQATTAT_LETTERS } from '../constants.ts';
import { getSliceAtPoint } from '../utils.ts';

interface TreeOfLifeModeProps {
  rotation: number;
  onClose: () => void;
}

const PRESET_1 = [
  "Book", "Chosen One | Rasul", "Sign", "Prophet", "Challenge | Rescue", "Curse", 
  "Blessed Land", "Believer | Servant", "Suhuf", "Teacher", "Witness | Driver", "Stone"
];

const PRESET_2 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Heifer",
  "Stone",
  "Boat | Bee",
  "Noah | Musa",
  "Idris | Isa",
  "Tree | Mountain",
  "Amanah",
  "Return",
  "Solomon | Dawud",
  "Book | Yahya"
];

const PRESET_3 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Rushd",
  "Stone",
  "Iron | Wood",
  "Noah | Musa",
  "Idris | Isa",
  "Iron | Mountain",
  "Amanah",
  "Dawud",
  "Solomon | Death",
  "Book | Yahya"
];

interface BifurcationStage {
  main: number[];
  manualLines: [number, number][];
  isBlackPhase?: boolean;
}

const TreeOfLifeMode: React.FC<TreeOfLifeModeProps> = ({ rotation, onClose }) => {
  const [labels, setLabels] = useState<string[]>(Array(12).fill(''));
  const [labelOffset, setLabelOffset] = useState(0); 
  const [isCycling, setIsCycling] = useState(false);
  const [activeMode, setActiveMode] = useState<'linear' | 'bifurcation'>('linear');
  const [highlightedNodes, setHighlightedNodes] = useState<number[]>([]);

  const [showLightning, setShowLightning] = useState(false);
  const [showExplosion, setShowExplosion] = useState(false);

  // Domain Node Sets
  const BLUE_NODES = [1, 2, 3, 4, 5, 6, 13];
  const GREEN_NODES = [12, 11, 10, 9, 8, 7, 15];

  const LOOP_LINES: [number, number][] = [[2, 3], [3, 6], [6, 9], [9, 11], [11, 10], [10, 7], [7, 4], [4, 2]];
  const BOLT_3_10_LINES: [number, number][] = [[3, 13], [4, 13], [4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9], [9, 15], [10, 15]];
  const BOLT_4_9_LINES: [number, number][] = [[4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9]];
  const PATH_5_8_LINES: [number, number][] = [[5, 6], [6, 14], [7, 14], [7, 8]];
  const CROSS_PLUS_LINES: [number, number][] = [[6, 14], [7, 14], [5, 14], [14, 8], [6, 7], [5, 8]];

  const DUAL_GROUP_LINES: [number, number][] = [
    [1, 2], [2, 3], [2, 4], [2, 13], [3, 13], [4, 13], [3, 5], [4, 5], [5, 6], [3, 6], [13, 5],
    [12, 11], [11, 10], [11, 9], [9, 15], [10, 15], [15, 8], [8, 9], [8, 10], [7, 8], [7, 10], [15, 11]
  ];
  const SQUARE_PLUS_LINES: [number, number][] = [[5, 6], [5, 7], [6, 8], [7, 8], [6, 14], [14, 7], [5, 14], [14, 8]];

  const BIFURCATION_STAGES: BifurcationStage[] = useMemo(() => [
    { main: [1, 12], manualLines: [], isBlackPhase: true },
    { main: [2, 11], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: CROSS_PLUS_LINES },
    { main: [12, 1], manualLines: DUAL_GROUP_LINES },
    { main: [11, 2], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: SQUARE_PLUS_LINES },
  ], []);

  const handleSyncFromWheel = (mode: 'full' | 'title') => {
    const newLabels = KATHARA_CLOCK_POINTS.map(pointValue => {
        const slice = getSliceAtPoint(pointValue, rotation);
        const chapterInfo = CHAPTER_DETAILS.find(c => c.number === slice.id);
        const title = chapterInfo?.englishName || 'Unknown';
        const letters = MUQATTAT_LETTERS.get(slice.id)?.join(' ') || '';
        if (mode === 'title') return `${title}${letters ? ` | ${letters}` : ''}`;
        return `${slice.id} ${title}${letters ? ` | ${letters}` : ''}`;
    });
    setLabels(newLabels);
    setLabelOffset(0);
  };

  const handlePreset = (num: number) => {
    setLabelOffset(0);
    setHighlightedNodes([]);
    setIsCycling(false);
    if (num === 0) setLabels(Array(12).fill(''));
    else if (num === 1) setLabels([...PRESET_1]);
    else if (num === 2) setLabels([...PRESET_2]);
    else if (num === 3) setLabels([...PRESET_3]);
  };

  const updateVisuals = useCallback((offset: number) => {
    if (activeMode === 'linear') setHighlightedNodes([offset + 1]);
    else setHighlightedNodes(BIFURCATION_STAGES[offset].main);
  }, [activeMode, BIFURCATION_STAGES]);

  const handleShift = useCallback((direction: 'up' | 'down') => {
    setLabelOffset((prev) => {
      const next = direction === 'up' ? (prev + 1) % 12 : (prev - 1 + 12) % 12;
      if (activeMode === 'bifurcation') {
        if (prev === 11 && next === 0) { setShowLightning(true); setTimeout(() => setShowLightning(false), 800); }
        if (prev === 5 && next === 6) { setShowExplosion(true); setTimeout(() => setShowExplosion(false), 1200); }
      }
      updateVisuals(next);
      return next;
    });
  }, [updateVisuals, activeMode]);

  useEffect(() => { updateVisuals(labelOffset); }, [activeMode, updateVisuals, labelOffset]);

  useEffect(() => {
    if (!isCycling) return;
    const intervalId = window.setInterval(() => { handleShift('up'); }, 1800);
    return () => clearInterval(intervalId);
  }, [isCycling, handleShift]);

  const updateLabel = (index: number, val: string) => {
    const next = [...labels];
    next[index] = val;
    setLabels(next);
  };

  const getLineStatus = useCallback((from: number, to: number, h: number[], offset: number) => {
    if (activeMode === 'linear') {
      const nodeId = h[0];
      return from === nodeId || to === nodeId ? 'main' : null;
    }
    const stage = BIFURCATION_STAGES[offset];
    if (stage.isBlackPhase) return 'black';
    const isManual = stage.manualLines?.some(l => (l[0] === from && l[1] === to) || (l[0] === to && l[1] === from));
    return isManual ? 'main' : null;
  }, [activeMode, BIFURCATION_STAGES]);

  const getDisplayIdx = useCallback((nodeIdx: number, offset: number, mode: 'linear' | 'bifurcation') => {
    if (mode === 'linear') return (nodeIdx - offset + 12) % 12;
    const step = offset % 6;
    const hasCrossed = offset >= 6;
    if (nodeIdx < 6) return hasCrossed ? (nodeIdx - step + 6) % 6 + 6 : (nodeIdx - step + 6) % 6;
    return hasCrossed ? (11 - nodeIdx - step + 6) % 6 : (11 - nodeIdx - step + 6) % 6 + 6;
  }, []);

  const renderDiagram = () => {
    const isPhase2or8 = activeMode === 'bifurcation' && (labelOffset === 1 || labelOffset === 7);
    const extraSilverLines = isPhase2or8 ? [[9, 7], [6, 4]] : [];

    return (
      <div className="relative flex items-center justify-center bg-black/80 overflow-hidden h-full w-full rounded-3xl lg:rounded-none">
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[90%] h-[90%] rounded-full bg-cyan-950/10 blur-[120px] lg:blur-[180px]"></div>
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000_100%)] opacity-80"></div>
        </div>

        <style>{`
          .node-glow { filter: drop-shadow(0 0 15px currentColor); }
          .kathara-svg { width: 100%; height: 100%; max-height: 85vh; padding: 20px; }
          .junction-box { stroke-width: 1; fill: rgba(0, 0, 0, 0.85); stroke: rgba(255, 255, 255, 0.1); }
          .active-junction { stroke: #fff; stroke-width: 1.5; fill: rgba(8, 145, 178, 0.3); }
          .filter-junction { stroke: #06b6d4; fill: rgba(0, 30, 40, 0.9); }

          @keyframes flow-up { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }
          @keyframes flow-down { 0% { stroke-dashoffset: 0; } 100% { stroke-dashoffset: 40; } }
          @keyframes flow-silver { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }

          .liquid-blue-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-up 1.6s linear infinite; filter: drop-shadow(0 0 6px #06b6d4); }
          .liquid-green-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-down 1.6s linear infinite; filter: drop-shadow(0 0 6px #4ade80); }
          .liquid-silver-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-silver 1.6s linear infinite; filter: drop-shadow(0 0 6px #cbd5e1); }

          @keyframes spark { 0%, 100% { opacity: 0; stroke-width: 1; } 20% { opacity: 1; stroke-width: 4; } 60% { opacity: 1; stroke-width: 2; } }
          .lightning-bolt { stroke: #fff; filter: drop-shadow(0 0 12px cyan); animation: spark 0.25s infinite; }

          @keyframes blast { 0% { transform: scale(0); opacity: 1; filter: blur(0px); } 50% { transform: scale(3); opacity: 0.5; filter: blur(5px); } 100% { transform: scale(4.5); opacity: 0; filter: blur(10px); } }
          .fire-burst { fill: #f97316; animation: blast 0.8s ease-out forwards; }
        `}</style>

        <svg viewBox="-70 0 290 280" className="kathara-svg drop-shadow-[0_0_80px_rgba(6,182,212,0.15)]">
          <defs>
            <linearGradient id="activeGrad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#0891b2" />
              <stop offset="100%" stopColor="#06b6d4" />
            </linearGradient>
          </defs>

          <g>
            {KATHARA_GRID_LINES.map((line, index) => {
              const fromNode = KATHARA_GRID_NODES.find(n => n.id === line.from);
              const toNode = KATHARA_GRID_NODES.find(n => n.id === line.to);
              if (!fromNode || !toNode) return null;

              const status = getLineStatus(line.from, line.to, highlightedNodes, labelOffset);
              const isMain = status === 'main';
              const isAscending = fromNode.y > toNode.y;

              const isBlueDomain = (BLUE_NODES.includes(line.from) && BLUE_NODES.includes(line.to)) || 
                                  ((line.from === 14 || line.to === 14) && (BLUE_NODES.includes(line.from) || BLUE_NODES.includes(line.to)));

              const isGreenDomain = (GREEN_NODES.includes(line.from) && GREEN_NODES.includes(line.to)) || 
                                   ((line.from === 14 || line.to === 14) && (GREEN_NODES.includes(line.from) || GREEN_NODES.includes(line.to)));

              const isPhase12 = activeMode === 'bifurcation' && labelOffset === 11;
              const isSilverLine = isPhase12 && (
                (line.from === 6 && line.to === 8) || (line.from === 8 && line.to === 6) ||
                (line.from === 8 && line.to === 7) || (line.from === 7 && line.to === 8) ||
                (line.from === 7 && line.to === 5) || (line.from === 5 && line.to === 7) ||
                (line.from === 5 && line.to === 6) || (line.from === 6 && line.to === 5)
              );

              const showBlue = activeMode === 'linear' ? isMain : (isMain && isBlueDomain && !isSilverLine);
              const showGreen = activeMode === 'linear' ? isMain : (isMain && isGreenDomain && !isSilverLine);
              const showSilver = isMain && isSilverLine;

              const dx = toNode.x - fromNode.x;
              const dy = toNode.y - fromNode.y;
              const len = Math.sqrt(dx*dx + dy*dy);
              const nx = -dy / (len || 1);
              const ny = dx / (len || 1);
              const offsetDist = activeMode === 'linear' ? 2.0 : 0;

              return (
                <g key={index}>
                  <line 
                    x1={fromNode.x} y1={fromNode.y} 
                    x2={toNode.x} y2={toNode.y} 
                    stroke={isMain ? (isSilverLine ? "rgba(203,213,225,0.2)" : "rgba(255,255,255,0.12)") : status === 'black' ? "#0a0a0a" : "rgba(255,255,255,0.04)"}
                    strokeWidth={isMain ? 4 : 1}
                    className="transition-all duration-700"
                  />
                  {showBlue && <line x1={(isAscending ? fromNode.x : toNode.x) + nx * offsetDist} y1={(isAscending ? fromNode.y : toNode.y) + ny * offsetDist} x2={(isAscending ? toNode.x : fromNode.x) + nx * offsetDist} y2={(isAscending ? toNode.y : fromNode.y) + ny * offsetDist} stroke="#06b6d4" strokeWidth="3.5" className="liquid-blue-flow" />}
                  {showGreen && <line x1={(isAscending ? toNode.x : fromNode.x) - nx * offsetDist} y1={(isAscending ? toNode.y : fromNode.y) - ny * offsetDist} x2={(isAscending ? fromNode.x : toNode.x) - nx * offsetDist} y2={(isAscending ? fromNode.y : toNode.y) - ny * offsetDist} stroke="#4ade80" strokeWidth="3.5" className="liquid-green-flow" />}
                  {showSilver && <line x1={fromNode.x} y1={fromNode.y} x2={toNode.x} y2={toNode.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />}
                </g>
              );
            })}
            {extraSilverLines.map(([fromId, toId], idx) => {
              const f = KATHARA_GRID_NODES.find(n => n.id === fromId);
              const t = KATHARA_GRID_NODES.find(n => n.id === toId);
              if (!f || !t) return null;
              return (
                <g key={`extra-silver-${idx}`}>
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="rgba(203,213,225,0.4)" strokeWidth="3" />
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />
                </g>
              );
            })}
          </g>

          {showLightning && (
            <g className="pointer-events-none">
              <path d="M 75 20 L 95 60 L 55 100 L 75 140" fill="none" className="lightning-bolt" />
              <path d="M 30 140 L 55 170 L 35 200 L 75 240" fill="none" className="lightning-bolt" />
              <path d="M 120 140 L 95 170 L 115 200 L 75 240" fill="none" className="lightning-bolt" />
            </g>
          )}

          {showExplosion && (
            <g transform="translate(75, 140)" className="pointer-events-none">
              <circle r="12" className="fire-burst" />
              <circle r="8" className="fire-burst" style={{ animationDelay: '0.1s' }} />
            </g>
          )}

          {KATHARA_GRID_NODES.map((node, nodeIdx) => {
            const isFilter = node.id > 12;
            const isHighlighted = highlightedNodes.includes(node.id);
            const displayLabelIdx = isFilter ? -1 : getDisplayIdx(nodeIdx, labelOffset, activeMode);
            const rawLabel = isFilter ? '' : labels[displayLabelIdx];

            // Combined triplet labels as requested
            const filterFullLabel = node.id === 13 ? '△108⚡' : node.id === 14 ? '🔥103🐟' : node.id === 15 ? '⚫110🌳' : null;

            const labelParts = rawLabel ? rawLabel.split('|').map(p => p.trim()) : [];
            const hasMultiple = labelParts.length > 1;
            const isSpineNode = node.x === 75 && node.id <= 12; 
            const isLeftSide = node.x < 75;

            return (
              <g key={node.id} className="transition-all duration-500">
                {isFilter ? (
                  <g>
                    {isHighlighted && <rect x={node.x-28} y={node.y-12} width="56" height="24" rx="4" fill="rgba(6,182,212,0.15)" className="animate-pulse" />}
                    <rect x={node.x-25} y={node.y-10} width="50" height="20" rx="3" className={`filter-junction ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#06b6d4' }} />
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#0891b2"} className="font-mono tracking-tighter" style={{ pointerEvents: 'none' }}>
                      {filterFullLabel}
                    </text>
                  </g>
                ) : (
                  <g>
                    <rect x={node.x-14} y={node.y-14} width="28" height="28" rx="6" className={`junction-box ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#fff' }} />
                    {isHighlighted && <circle cx={node.x} cy={node.y} r={22} fill="url(#activeGrad)" opacity="0.1" className="animate-pulse" />}
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="8" fontWeight="black" fill={isHighlighted ? "#fff" : "#555"}>{node.id}</text>
                    {rawLabel && (
                      <g className="pointer-events-none">
                         {isSpineNode && hasMultiple ? (
                          <>
                            <rect x={node.x - 76} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x - 22} y={node.y} textAnchor="end" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[0]}</text>
                            <rect x={node.x + 18} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x + 22} y={node.y} textAnchor="start" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[1]}</text>
                          </>
                         ) : (
                          <g>
                             <rect x={isLeftSide ? node.x - 76 : node.x + 18} y={node.y - (hasMultiple ? 14 : 9)} width="58" height={hasMultiple ? 28 : 18} rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                             <text x={isLeftSide ? node.x - 22 : node.x + 22} y={node.y} textAnchor={isLeftSide ? "end" : "start"} dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">
                               {hasMultiple ? (<><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="-0.5em">{labelParts[0]}</tspan><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="1.1em">{labelParts[1]}</tspan></>) : rawLabel}
                             </text>
                          </g>
                         )}
                      </g>
                    )}
                  </g>
                )}
              </g>
            );
          })}
        </svg>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#02040a] animate-in fade-in zoom-in duration-500 overflow-y-auto lg:overflow-hidden">
      <aside className="w-full lg:w-[420px] h-fit lg:h-full p-8 border-b lg:border-r border-white/10 flex flex-col space-y-6 bg-black/40 backdrop-blur-xl shrink-0 overflow-visible lg:overflow-y-auto custom-scrollbar">
        <div className="flex justify-between items-start shrink-0">
          <div className="space-y-1">
            <h2 className="text-2xl font-black text-white tracking-tighter uppercase italic leading-tight">
              Photosynthesis:
              <span className="block text-xs md:text-sm font-bold tracking-widest text-cyan-400 mt-1 not-italic">
                Harvesting Love and Intelligence in Form
              </span>
            </h2>
            <div className="flex flex-wrap gap-1.5 mt-2">
               {[0, 1, 2, 3].map(n => (
                 <button key={n} onClick={() => handlePreset(n)} className={`w-9 h-9 rounded-lg border font-black text-[10px] transition-all ${n === 0 ? 'bg-white/5 border-white/10 text-gray-500' : 'bg-cyan-950/20 border-cyan-500/30 text-cyan-400 hover:bg-cyan-500 hover:text-black'}`}>
                   {n === 0 ? 'CLR' : `P${n}`}
                 </button>
               ))}
               <button onClick={() => handleSyncFromWheel('full')} className="px-3 h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 1</button>
               <button onClick={() => handleSyncFromWheel('title')} className="px-3 h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 2</button>
            </div>
          </div>
          <button onClick={onClose} className="p-3 rounded-2xl bg-white/5 text-gray-400 hover:text-white transition-all hover:bg-white/10 shrink-0">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="flex-1 space-y-4 pr-1">
          {labels.map((label, idx) => {
            let mappedNodeId = -1;
            for(let ni=0; ni<12; ni++) {
              if(getDisplayIdx(ni, labelOffset, activeMode) === idx) {
                mappedNodeId = ni + 1;
                break;
              }
            }
            const isCurrentlyActive = highlightedNodes.includes(mappedNodeId);

            return (
              <div key={idx} className={`group relative p-0.5 transition-all duration-300 ${isCurrentlyActive ? 'scale-[1.02]' : ''}`}>
                <div className="flex justify-between items-end mb-1 px-1">
                  <label className="text-[9px] text-gray-500 uppercase tracking-widest font-black block">Leaf {idx + 1}</label>
                  <span className={`text-[8px] font-mono px-1.5 py-0.5 rounded border transition-colors ${isCurrentlyActive ? 'bg-cyan-500/20 border-cyan-500 text-cyan-200' : 'bg-white/5 border-white/10 text-gray-600'}`}>
                    NODE: {mappedNodeId}
                  </span>
                </div>
                <input 
                  type="text" value={label} onChange={(e) => updateLabel(idx, e.target.value)} placeholder={`Terminal input ${idx + 1}...`}
                  className={`w-full bg-white/5 border rounded-xl px-4 py-3 text-sm font-medium focus:bg-cyan-950/10 outline-none transition-all placeholder-gray-800 ${isCurrentlyActive ? 'border-cyan-500/50 text-white' : 'border-white/5 text-cyan-50/70'}`}
                />
              </div>
            );
          })}
        </div>

        <div className="pt-6 border-t border-white/5 space-y-4 shrink-0 pb-6 bg-black/20 -mx-8 px-8">
          <div className="flex justify-between items-baseline px-1">
            <h3 className="text-xs font-black text-gray-500 uppercase tracking-[0.2em]">SYSTEM NAVIGATION</h3>
            <span className="font-mono text-[11px] text-cyan-500 px-2 py-0.5 rounded bg-cyan-950/30">Phase: {labelOffset + 1}</span>
          </div>
          <div className="flex p-1 bg-white/5 rounded-2xl gap-1">
            <button onClick={() => { setActiveMode('linear'); setIsCycling(false); }} className={`flex-1 py-3 rounded-xl text-[10px] font-black tracking-widest transition-all ${activeMode === 'linear' ? 'bg-cyan-500 text-black shadow-lg shadow-cyan-500/20' : 'text-gray-400'}`}>LINEAR</button>
            <button onClick={() => { setActiveMode('bifurcation'); setIsCycling(false); }} className={`flex-1 py-3 rounded-xl text-[10px] font-black tracking-widest transition-all ${activeMode === 'bifurcation' ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-600/20' : 'text-gray-400'}`}>BIFURCATE</button>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => handleShift('down')} className="bg-white/5 hover:bg-cyan-500/10 py-4 rounded-2xl border border-white/5 text-[10px] font-black tracking-widest transition-all uppercase">Prev Step</button>
            <button onClick={() => handleShift('up')} className="bg-white/5 hover:bg-cyan-500/10 py-4 rounded-2xl border border-white/5 text-[10px] font-black tracking-widest transition-all uppercase">Next Step</button>
          </div>
          <button onClick={() => setIsCycling(!isCycling)} className={`w-full py-4 rounded-2xl border font-black text-[11px] tracking-[0.2em] transition-all uppercase ${isCycling ? 'bg-red-600 text-white shadow-xl' : 'bg-cyan-600/10 text-cyan-400 border-cyan-500/20 hover:border-cyan-500/50'}`}>
            {isCycling ? 'Stop Stream' : `Animate Stream`}
          </button>
        </div>
      </aside>

      <div className="flex-1 h-[70vh] lg:h-full flex items-center justify-center p-4 lg:p-12">
        <div className="w-full h-full max-w-5xl max-h-screen flex items-center justify-center">
          {renderDiagram()}
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(6, 182, 212, 0.15); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(6, 182, 212, 0.3); }
      `}</style>
    </div>
  );
};

export default TreeOfLifeMode;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { KATHARA_GRID_NODES, KATHARA_GRID_LINES, KATHARA_CLOCK_POINTS, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, MUQATTAT_LETTERS } from '../constants.ts';
import { getSliceAtPoint } from '../utils.ts';

interface TreeOfLifeModeProps {
  rotation: number;
  onClose: () => void;
}

const PRESET_1 = [
  "Book", "Chosen One | Rasul", "Sign", "Prophet", "Challenge | Rescue", "Curse", 
  "Blessed Land", "Believer | Servant", "Suhuf", "Teacher", "Witness | Driver", "Stone"
];

const PRESET_2 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Heifer",
  "Stone",
  "Boat | Bee",
  "Noah | Musa",
  "Idris | Isa",
  "Tree | Mountain",
  "Amanah",
  "Return",
  "Solomon | Dawud",
  "Book | Yahya"
];

const PRESET_3 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Rushd",
  "Stone",
  "Iron | Wood",
  "Noah | Musa",
  "Idris | Isa",
  "Iron | Mountain",
  "Amanah",
  "Dawud",
  "Solomon | Death",
  "Book | Yahya"
];

interface BifurcationStage {
  main: number[];
  manualLines: [number, number][];
  isBlackPhase?: boolean;
}

const TreeOfLifeMode: React.FC<TreeOfLifeModeProps> = ({ rotation, onClose }) => {
  const [labels, setLabels] = useState<string[]>(Array(12).fill(''));
  const [labelOffset, setLabelOffset] = useState(0); 
  const [isCycling, setIsCycling] = useState(false);
  const [activeMode, setActiveMode] = useState<'linear' | 'bifurcation'>('linear');
  const [highlightedNodes, setHighlightedNodes] = useState<number[]>([]);

  const [showLightning, setShowLightning] = useState(false);
  const [showExplosion, setShowExplosion] = useState(false);

  // Domain Node Sets
  const BLUE_NODES = [1, 2, 3, 4, 5, 6, 13];
  const GREEN_NODES = [12, 11, 10, 9, 8, 7, 15];

  const LOOP_LINES: [number, number][] = [[2, 3], [3, 6], [6, 9], [9, 11], [11, 10], [10, 7], [7, 4], [4, 2]];
  const BOLT_3_10_LINES: [number, number][] = [[3, 13], [4, 13], [4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9], [9, 15], [10, 15]];
  const BOLT_4_9_LINES: [number, number][] = [[4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9]];
  const PATH_5_8_LINES: [number, number][] = [[5, 6], [6, 14], [7, 14], [7, 8]];
  const CROSS_PLUS_LINES: [number, number][] = [[6, 14], [7, 14], [5, 14], [14, 8], [6, 7], [5, 8]];

  const DUAL_GROUP_LINES: [number, number][] = [
    [1, 2], [2, 3], [2, 4], [2, 13], [3, 13], [4, 13], [3, 5], [4, 5], [5, 6], [3, 6], [13, 5],
    [12, 11], [11, 10], [11, 9], [9, 15], [10, 15], [15, 8], [8, 9], [8, 10], [7, 8], [7, 10], [15, 11]
  ];
  const SQUARE_PLUS_LINES: [number, number][] = [[5, 6], [5, 7], [6, 8], [7, 8], [6, 14], [14, 7], [5, 14], [14, 8]];

  const BIFURCATION_STAGES: BifurcationStage[] = useMemo(() => [
    { main: [1, 12], manualLines: [], isBlackPhase: true },
    { main: [2, 11], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: CROSS_PLUS_LINES },
    { main: [12, 1], manualLines: DUAL_GROUP_LINES },
    { main: [11, 2], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: SQUARE_PLUS_LINES },
  ], []);

  const handleSyncFromWheel = (mode: 'full' | 'title') => {
    const newLabels = KATHARA_CLOCK_POINTS.map(pointValue => {
        const slice = getSliceAtPoint(pointValue, rotation);
        const chapterInfo = CHAPTER_DETAILS.find(c => c.number === slice.id);
        const title = chapterInfo?.englishName || 'Unknown';
        const letters = MUQATTAT_LETTERS.get(slice.id)?.join(' ') || '';
        if (mode === 'title') return `${title}${letters ? ` | ${letters}` : ''}`;
        return `${slice.id} ${title}${letters ? ` | ${letters}` : ''}`;
    });
    setLabels(newLabels);
    setLabelOffset(0);
  };

  const handlePreset = (num: number) => {
    setLabelOffset(0);
    setHighlightedNodes([]);
    setIsCycling(false);
    if (num === 0) setLabels(Array(12).fill(''));
    else if (num === 1) setLabels([...PRESET_1]);
    else if (num === 2) setLabels([...PRESET_2]);
    else if (num === 3) setLabels([...PRESET_3]);
  };

  const updateVisuals = useCallback((offset: number) => {
    if (activeMode === 'linear') setHighlightedNodes([offset + 1]);
    else setHighlightedNodes(BIFURCATION_STAGES[offset].main);
  }, [activeMode, BIFURCATION_STAGES]);

  const handleShift = useCallback((direction: 'up' | 'down') => {
    setLabelOffset((prev) => {
      const next = direction === 'up' ? (prev + 1) % 12 : (prev - 1 + 12) % 12;
      if (activeMode === 'bifurcation') {
        if (prev === 11 && next === 0) { setShowLightning(true); setTimeout(() => setShowLightning(false), 800); }
        if (prev === 5 && next === 6) { setShowExplosion(true); setTimeout(() => setShowExplosion(false), 1200); }
      }
      updateVisuals(next);
      return next;
    });
  }, [updateVisuals, activeMode]);

  useEffect(() => { updateVisuals(labelOffset); }, [activeMode, updateVisuals, labelOffset]);

  useEffect(() => {
    if (!isCycling) return;
    const intervalId = window.setInterval(() => { handleShift('up'); }, 1800);
    return () => clearInterval(intervalId);
  }, [isCycling, handleShift]);

  const updateLabel = (index: number, val: string) => {
    const next = [...labels];
    next[index] = val;
    setLabels(next);
  };

  const getLineStatus = useCallback((from: number, to: number, h: number[], offset: number) => {
    if (activeMode === 'linear') {
      const nodeId = h[0];
      return from === nodeId || to === nodeId ? 'main' : null;
    }
    const stage = BIFURCATION_STAGES[offset];
    if (stage.isBlackPhase) return 'black';
    const isManual = stage.manualLines?.some(l => (l[0] === from && l[1] === to) || (l[0] === to && l[1] === from));
    return isManual ? 'main' : null;
  }, [activeMode, BIFURCATION_STAGES]);

  const getDisplayIdx = useCallback((nodeIdx: number, offset: number, mode: 'linear' | 'bifurcation') => {
    if (mode === 'linear') return (nodeIdx - offset + 12) % 12;
    const step = offset % 6;
    const hasCrossed = offset >= 6;
    if (nodeIdx < 6) return hasCrossed ? (nodeIdx - step + 6) % 6 + 6 : (nodeIdx - step + 6) % 6;
    return hasCrossed ? (11 - nodeIdx - step + 6) % 6 : (11 - nodeIdx - step + 6) % 6 + 6;
  }, []);

  const renderDiagram = () => {
    const isPhase2or8 = activeMode === 'bifurcation' && (labelOffset === 1 || labelOffset === 7);
    const extraSilverLines = isPhase2or8 ? [[9, 7], [6, 4]] : [];

    return (
      <div className="relative flex items-center justify-center bg-black/80 overflow-hidden h-full w-full rounded-3xl lg:rounded-none">
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[90%] h-[90%] rounded-full bg-cyan-950/10 blur-[120px] lg:blur-[180px]"></div>
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000_100%)] opacity-80"></div>
        </div>

        <style>{`
          .node-glow { filter: drop-shadow(0 0 15px currentColor); }
          .kathara-svg { width: 100%; height: 100%; max-height: 85vh; padding: 20px; }
          .junction-box { stroke-width: 1; fill: rgba(0, 0, 0, 0.85); stroke: rgba(255, 255, 255, 0.1); }
          .active-junction { stroke: #fff; stroke-width: 1.5; fill: rgba(8, 145, 178, 0.3); }
          .filter-junction { stroke: #06b6d4; fill: rgba(0, 30, 40, 0.9); }

          @keyframes flow-up { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }
          @keyframes flow-down { 0% { stroke-dashoffset: 0; } 100% { stroke-dashoffset: 40; } }
          @keyframes flow-silver { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }

          .liquid-blue-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-up 1.6s linear infinite; filter: drop-shadow(0 0 6px #06b6d4); }
          .liquid-green-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-down 1.6s linear infinite; filter: drop-shadow(0 0 6px #4ade80); }
          .liquid-silver-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-silver 1.6s linear infinite; filter: drop-shadow(0 0 6px #cbd5e1); }

          @keyframes spark { 0%, 100% { opacity: 0; stroke-width: 1; } 20% { opacity: 1; stroke-width: 4; } 60% { opacity: 1; stroke-width: 2; } }
          .lightning-bolt { stroke: #fff; filter: drop-shadow(0 0 12px cyan); animation: spark 0.25s infinite; }

          @keyframes blast { 0% { transform: scale(0); opacity: 1; filter: blur(0px); } 50% { transform: scale(3); opacity: 0.5; filter: blur(5px); } 100% { transform: scale(4.5); opacity: 0; filter: blur(10px); } }
          .fire-burst { fill: #f97316; animation: blast 0.8s ease-out forwards; }
        `}</style>

        <svg viewBox="-70 0 290 280" className="kathara-svg drop-shadow-[0_0_80px_rgba(6,182,212,0.15)]">
          <defs>
            <linearGradient id="activeGrad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#0891b2" />
              <stop offset="100%" stopColor="#06b6d4" />
            </linearGradient>
          </defs>

          <g>
            {KATHARA_GRID_LINES.map((line, index) => {
              const fromNode = KATHARA_GRID_NODES.find(n => n.id === line.from);
              const toNode = KATHARA_GRID_NODES.find(n => n.id === line.to);
              if (!fromNode || !toNode) return null;

              const status = getLineStatus(line.from, line.to, highlightedNodes, labelOffset);
              const isMain = status === 'main';
              const isAscending = fromNode.y > toNode.y;

              const isBlueDomain = (BLUE_NODES.includes(line.from) && BLUE_NODES.includes(line.to)) || 
                                  ((line.from === 14 || line.to === 14) && (BLUE_NODES.includes(line.from) || BLUE_NODES.includes(line.to)));

              const isGreenDomain = (GREEN_NODES.includes(line.from) && GREEN_NODES.includes(line.to)) || 
                                   ((line.from === 14 || line.to === 14) && (GREEN_NODES.includes(line.from) || GREEN_NODES.includes(line.to)));

              const isPhase12 = activeMode === 'bifurcation' && labelOffset === 11;
              const isSilverLine = isPhase12 && (
                (line.from === 6 && line.to === 8) || (line.from === 8 && line.to === 6) ||
                (line.from === 8 && line.to === 7) || (line.from === 7 && line.to === 8) ||
                (line.from === 7 && line.to === 5) || (line.from === 5 && line.to === 7) ||
                (line.from === 5 && line.to === 6) || (line.from === 6 && line.to === 5)
              );

              const showBlue = activeMode === 'linear' ? isMain : (isMain && isBlueDomain && !isSilverLine);
              const showGreen = activeMode === 'linear' ? isMain : (isMain && isGreenDomain && !isSilverLine);
              const showSilver = isMain && isSilverLine;

              const dx = toNode.x - fromNode.x;
              const dy = toNode.y - fromNode.y;
              const len = Math.sqrt(dx*dx + dy*dy);
              const nx = -dy / (len || 1);
              const ny = dx / (len || 1);
              const offsetDist = activeMode === 'linear' ? 2.0 : 0;

              return (
                <g key={index}>
                  <line 
                    x1={fromNode.x} y1={fromNode.y} 
                    x2={toNode.x} y2={toNode.y} 
                    stroke={isMain ? (isSilverLine ? "rgba(203,213,225,0.2)" : "rgba(255,255,255,0.12)") : status === 'black' ? "#0a0a0a" : "rgba(255,255,255,0.04)"}
                    strokeWidth={isMain ? 4 : 1}
                    className="transition-all duration-700"
                  />
                  {showBlue && <line x1={(isAscending ? fromNode.x : toNode.x) + nx * offsetDist} y1={(isAscending ? fromNode.y : toNode.y) + ny * offsetDist} x2={(isAscending ? toNode.x : fromNode.x) + nx * offsetDist} y2={(isAscending ? toNode.y : fromNode.y) + ny * offsetDist} stroke="#06b6d4" strokeWidth="3.5" className="liquid-blue-flow" />}
                  {showGreen && <line x1={(isAscending ? toNode.x : fromNode.x) - nx * offsetDist} y1={(isAscending ? toNode.y : fromNode.y) - ny * offsetDist} x2={(isAscending ? fromNode.x : toNode.x) - nx * offsetDist} y2={(isAscending ? fromNode.y : toNode.y) - ny * offsetDist} stroke="#4ade80" strokeWidth="3.5" className="liquid-green-flow" />}
                  {showSilver && <line x1={fromNode.x} y1={fromNode.y} x2={toNode.x} y2={toNode.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />}
                </g>
              );
            })}
            {extraSilverLines.map(([fromId, toId], idx) => {
              const f = KATHARA_GRID_NODES.find(n => n.id === fromId);
              const t = KATHARA_GRID_NODES.find(n => n.id === toId);
              if (!f || !t) return null;
              return (
                <g key={`extra-silver-${idx}`}>
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="rgba(203,213,225,0.4)" strokeWidth="3" />
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />
                </g>
              );
            })}
          </g>

          {showLightning && (
            <g className="pointer-events-none">
              <path d="M 75 20 L 95 60 L 55 100 L 75 140" fill="none" className="lightning-bolt" />
              <path d="M 30 140 L 55 170 L 35 200 L 75 240" fill="none" className="lightning-bolt" />
              <path d="M 120 140 L 95 170 L 115 200 L 75 240" fill="none" className="lightning-bolt" />
            </g>
          )}

          {showExplosion && (
            <g transform="translate(75, 140)" className="pointer-events-none">
              <circle r="12" className="fire-burst" />
              <circle r="8" className="fire-burst" style={{ animationDelay: '0.1s' }} />
            </g>
          )}

          {KATHARA_GRID_NODES.map((node, nodeIdx) => {
            const isFilter = node.id > 12;
            const isHighlighted = highlightedNodes.includes(node.id);
            const displayLabelIdx = isFilter ? -1 : getDisplayIdx(nodeIdx, labelOffset, activeMode);
            const rawLabel = isFilter ? '' : labels[displayLabelIdx];

            // Combined triplet labels as requested
            const filterFullLabel = node.id === 13 ? '△108⚡' : node.id === 14 ? '🔥103🐟' : node.id === 15 ? '⚫110🌳' : null;

            const labelParts = rawLabel ? rawLabel.split('|').map(p => p.trim()) : [];
            const hasMultiple = labelParts.length > 1;
            const isSpineNode = node.x === 75 && node.id <= 12; 
            const isLeftSide = node.x < 75;

            return (
              <g key={node.id} className="transition-all duration-500">
                {isFilter ? (
                  <g>
                    {isHighlighted && <rect x={node.x-28} y={node.y-12} width="56" height="24" rx="4" fill="rgba(6,182,212,0.15)" className="animate-pulse" />}
                    <rect x={node.x-25} y={node.y-10} width="50" height="20" rx="3" className={`filter-junction ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#06b6d4' }} />
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#0891b2"} className="font-mono tracking-tighter" style={{ pointerEvents: 'none' }}>
                      {filterFullLabel}
                    </text>
                  </g>
                ) : (
                  <g>
                    <rect x={node.x-14} y={node.y-14} width="28" height="28" rx="6" className={`junction-box ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#fff' }} />
                    {isHighlighted && <circle cx={node.x} cy={node.y} r={22} fill="url(#activeGrad)" opacity="0.1" className="animate-pulse" />}
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="8" fontWeight="black" fill={isHighlighted ? "#fff" : "#555"}>{node.id}</text>
                    {rawLabel && (
                      <g className="pointer-events-none">
                         {isSpineNode && hasMultiple ? (
                          <>
                            <rect x={node.x - 76} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x - 22} y={node.y} textAnchor="end" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[0]}</text>
                            <rect x={node.x + 18} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x + 22} y={node.y} textAnchor="start" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[1]}</text>
                          </>
                         ) : (
                          <g>
                             <rect x={isLeftSide ? node.x - 76 : node.x + 18} y={node.y - (hasMultiple ? 14 : 9)} width="58" height={hasMultiple ? 28 : 18} rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                             <text x={isLeftSide ? node.x - 22 : node.x + 22} y={node.y} textAnchor={isLeftSide ? "end" : "start"} dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">
                               {hasMultiple ? (<><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="-0.5em">{labelParts[0]}</tspan><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="1.1em">{labelParts[1]}</tspan></>) : rawLabel}
                             </text>
                          </g>
                         )}
                      </g>
                    )}
                  </g>
                )}
              </g>
            );
          })}
        </svg>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#02040a] animate-in fade-in zoom-in duration-500 overflow-y-auto lg:overflow-hidden">
      <aside className="w-full lg:w-[420px] h-fit lg:h-full p-8 border-b lg:border-r border-white/10 flex flex-col space-y-6 bg-black/40 backdrop-blur-xl shrink-0 overflow-visible lg:overflow-y-auto custom-scrollbar">
        <div className="flex justify-between items-start shrink-0">
          <div className="space-y-1">
            <h2 className="text-2xl font-black text-white tracking-tighter uppercase italic leading-tight">
              Photosynthesis:
              <span className="block text-xs md:text-sm font-bold tracking-widest text-cyan-400 mt-1 not-italic">
                Harvesting Love and Intelligence in Form
              </span>
            </h2>
            <div className="flex flex-wrap gap-1.5 mt-2">
               {[0, 1, 2, 3].map(n => (
                 <button key={n} onClick={() => handlePreset(n)} className={`w-9 h-9 rounded-lg border font-black text-[10px] transition-all ${n === 0 ? 'bg-white/5 border-white/10 text-gray-500' : 'bg-cyan-950/20 border-cyan-500/30 text-cyan-400 hover:bg-cyan-500 hover:text-black'}`}>
                   {n === 0 ? 'CLR' : `P${n}`}
                 </button>
               ))}
               <button onClick={() => handleSyncFromWheel('full')} className="px-3 h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 1</button>
               <button onClick={() => handleSyncFromWheel('title')} className="px-3 h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 2</button>
            </div>
          </div>
          <button onClick={onClose} className="p-3 rounded-2xl bg-white/5 text-gray-400 hover:text-white transition-all hover:bg-white/10 shrink-0">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="flex-1 space-y-4 pr-1">
          {labels.map((label, idx) => {
            let mappedNodeId = -1;
            for(let ni=0; ni<12; ni++) {
              if(getDisplayIdx(ni, labelOffset, activeMode) === idx) {
                mappedNodeId = ni + 1;
                break;
              }
            }
            const isCurrentlyActive = highlightedNodes.includes(mappedNodeId);

            return (
              <div key={idx} className={`group relative p-0.5 transition-all duration-300 ${isCurrentlyActive ? 'scale-[1.02]' : ''}`}>
                <div className="flex justify-between items-end mb-1 px-1">
                  <label className="text-[9px] text-gray-500 uppercase tracking-widest font-black block">Leaf {idx + 1}</label>
                </div>
                <input 
                  type="text" value={label} onChange={(e) => updateLabel(idx, e.target.value)} placeholder={`Terminal input ${idx + 1}...`}
                  className={`w-full bg-white/5 border rounded-xl px-4 py-3 text-sm font-medium focus:bg-cyan-950/10 outline-none transition-all placeholder-gray-800 ${isCurrentlyActive ? 'border-cyan-500/50 text-white' : 'border-white/5 text-cyan-50/70'}`}
                />
              </div>
            );
          })}
        </div>

        <div className="pt-6 border-t border-white/5 space-y-4 shrink-0 pb-6 bg-black/20 -mx-8 px-8">
          <div className="flex justify-between items-baseline px-1">
            <h3 className="text-xs font-black text-gray-500 uppercase tracking-[0.2em]">Flow of Life</h3>
            <span className="font-mono text-[11px] text-cyan-500 px-2 py-0.5 rounded bg-cyan-950/30">Phase: {labelOffset + 1}</span>
          </div>
          <div className="flex p-1 bg-white/5 rounded-2xl gap-1">
            <button onClick={() => { setActiveMode('linear'); setIsCycling(false); }} className={`flex-1 py-3 rounded-xl text-[10px] font-black tracking-widest transition-all ${activeMode === 'linear' ? 'bg-cyan-500 text-black shadow-lg shadow-cyan-500/20' : 'text-gray-400'}`}>LINEAR</button>
            <button onClick={() => { setActiveMode('bifurcation'); setIsCycling(false); }} className={`flex-1 py-3 rounded-xl text-[10px] font-black tracking-widest transition-all ${activeMode === 'bifurcation' ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-600/20' : 'text-gray-400'}`}>BIFURCATE</button>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => handleShift('down')} className="bg-white/5 hover:bg-cyan-500/10 py-4 rounded-2xl border border-white/5 text-lg font-black tracking-widest transition-all uppercase">-</button>
            <button onClick={() => handleShift('up')} className="bg-white/5 hover:bg-cyan-500/10 py-4 rounded-2xl border border-white/5 text-lg font-black tracking-widest transition-all uppercase">+</button>
          </div>
          <button onClick={() => setIsCycling(!isCycling)} className={`w-full py-4 rounded-2xl border font-black text-[11px] tracking-[0.2em] transition-all uppercase ${isCycling ? 'bg-red-600 text-white shadow-xl' : 'bg-cyan-600/10 text-cyan-400 border-cyan-500/20 hover:border-cyan-500/50'}`}>
            {isCycling ? 'Stop Stream' : `Animate Stream`}
          </button>
        </div>
      </aside>

      <div className="flex-1 h-[70vh] lg:h-full flex items-center justify-center p-4 lg:p-12">
        <div className="w-full h-full max-w-5xl max-h-screen flex items-center justify-center">
          {renderDiagram()}
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(6, 182, 212, 0.15); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(6, 182, 212, 0.3); }
      `}</style>
    </div>
  );
};

export default TreeOfLifeMode;
